	/* --- Style Linh Căn --- */

	/* 1. Khung hiển thị chung */
	.linggen-result-frame {
		border-radius: 8px;
		padding: 20px;
		margin-top: 15px;
		transition: all 0.5s ease-in-out;
		animation: fadeIn 0.8s ease-in-out;
	}
	@keyframes fadeIn { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }

	/* 2. Khung "Siêu Tiêu Cực" (cost < -1000) - Vận Rủi Thế Kỷ */
	.linggen-frame-super-negative {
		background: radial-gradient(circle at center, #1a1a1a, #000), url('https://www.transparenttextures.com/patterns/subtle-grunge.png');
		border: 2px solid #5a1212;
		box-shadow: 0 0 10px #c62828, inset 0 0 40px black;
		/* Animation chớp tắt, bất ổn */
		animation: demonic-flicker 3s infinite linear, fadeIn 0.8s ease-in-out;
	}

	/* Quả cầu bị hắc hóa, chỉ còn le lói ánh sáng bị giam cầm */
	.linggen-frame-super-negative .linggen-orb {
		background: radial-gradient(circle at center, #424242 0%, #1a1a1a 70%, black 100%);
		border-color: #c62828;
		/* Hiệu ứng bóng tối lan tỏa */
		box-shadow: inset 0 0 20px black, 0 0 10px #000;
		animation: corruption-pulse 4s infinite ease-in-out;
	}

	/* Thẻ tên cũng mang màu máu và đen */
	.linggen-frame-super-negative .linggen-tag {
		background: #c62828;
		color: #e0e0e0;
		text-shadow: 0 0 5px black;
	}

	/* Tên Linh Căn có màu đỏ máu */
	.linggen-frame-super-negative .linggen-frame-header h4 {
		color: #ff8a80;
		text-shadow: 0 0 10px #c62828, 0 0 5px black;
	}

	/* Hộp mô tả đồng bộ hoàn toàn */
	.creation-desc-box.linggen-frame-super-negative {
		border-color: #5a1212;
		background-color: rgba(0, 0, 0, 0.5);
		color: #ef9a9a;
		box-shadow: 0 0 15px rgba(255, 0, 0, 0.6);
		animation: demonic-flicker 3s infinite linear;
	}

	/* Định nghĩa các animation */
	@keyframes demonic-flicker {
		0%, 100% { box-shadow: 0 0 10px #c62828, inset 0 0 40px black; border-color: #5a1212; }
		50% { box-shadow: 0 0 20px #ff1744, inset 0 0 45px #1a1a1a; border-color: #ff1744; }
	}

	@keyframes corruption-pulse {
		0%, 100% { transform: scale(1); box-shadow: inset 0 0 20px black, 0 0 10px #000; }
		50% { transform: scale(0.98); box-shadow: inset 0 0 30px #1a1a1a, 0 0 15px #000; }
	}

	/* 3. Khung "Tiêu Cực" - Ma hồn quỷ ám */
	.linggen-frame-negative {
		background-color: #1a231a;
		border: 2px solid #2e7d32;
		box-shadow: inset 0 0 20px rgba(0, 0, 0, 0.6);
	}
	.linggen-frame-negative .linggen-orb {
		background: radial-gradient(circle, #424242, #1b5e20);
		border-color: #81c784;
		filter: blur(0.5px);
	}
	.linggen-frame-negative .linggen-tag { background: #2e7d32; }

	/* 4. Khung "Phổ Thông" */
	.linggen-frame-common {
		background-color: rgba(255, 255, 255, 0.05);
		border: 1px solid #5a4e3c;
	}
	.linggen-frame-common .linggen-orb { background: radial-gradient(circle, #e1bee7, #8e24aa); border-color: #6a1b9a; }
	.linggen-frame-common .linggen-tag { background: #8e24aa; }

	/* 5. Khung "Hiếm Có" */
	.linggen-frame-rare {
		background: radial-gradient(ellipse at bottom, #1a2a3a, #2c3e50);
		border: 2px solid #4fc3f7;
		box-shadow: inset 0 0 25px rgba(79, 195, 247, 0.2), 0 0 15px rgba(79, 195, 247, 0.4);
	}
	.linggen-frame-rare .linggen-orb { background: radial-gradient(circle, #81d4fa, #039be5); border-color: #0277bd; }
	.linggen-frame-rare .linggen-tag { background: #4fc3f7; color: #1a1a1a; }

	/* 6. Khung "Sử Thi" - Cầu vồng */
	.linggen-frame-epic {
		background-color: #1a1a1a; /* Nền tĩnh màu đen */
		border: 4px solid transparent; /* Đặt độ dày cho viền */
		border-image: linear-gradient(60deg, #ba68c8, #f06292, #ffd54f, #81c784, #4fc3f7, #7986cb) 1;
		animation: fadeIn 0.8s ease-in-out; /* Chỉ giữ lại animation xuất hiện */
	}

	.linggen-frame-epic .linggen-orb {
		border-color: rgba(255, 255, 255, 0.5);
		background: linear-gradient(60deg, #ba68c8, #f06292, #ffd54f, #81c784, #4fc3f7, #7986cb);
		background-size: 300% 300%;
		animation: rainbow-bg 4s ease infinite; /* Giữ animation cầu vồng cho quả cầu */
	}

	/* Đừng quên định nghĩa animation này nếu nó chưa có */
	@keyframes rainbow-bg {
		0%{background-position:0% 50%}
		50%{background-position:100% 50%}
		100%{background-position:0% 50%}
	}
	/* 7. Khung "Truyền Thuyết" - Cam sặc sỡ */
	.linggen-frame-legendary {
		background: radial-gradient(ellipse at bottom, #4a3720, #2c2a2a);
		border: 2px solid #ffd700;
		animation: legendary-glow 2.5s infinite alternate, fadeIn 0.8s ease-in-out;
	}
	@keyframes legendary-glow {
		from { box-shadow: inset 0 0 25px rgba(255, 215, 0, 0.3), 0 0 25px rgba(255, 215, 0, 0.7); }
		to { box-shadow: inset 0 0 30px rgba(255, 215, 0, 0.5), 0 0 40px rgba(255, 165, 0, 1); }
	}
	.linggen-frame-legendary .linggen-orb {
		background: radial-gradient(circle, #ffecb3, #ff8f00);
		border-color: #ffd700;
		animation: legendary-orb-glow 2s infinite alternate;
	}
	.linggen-frame-legendary .linggen-tag { background: #ffd700; color: #1a1a1a; }
	@keyframes legendary-orb-glow {
		from { box-shadow: 0 0 10px #ffc107, inset 0 0 10px #fff; }
		to { box-shadow: 0 0 25px #ff8f00, inset 0 0 15px #fffde7; }
	}

	/* --- Logic đồng bộ cho khung mô tả --- */
	.creation-desc-box { transition: all 0.5s ease; }
	.creation-desc-box.linggen-frame-negative { border-color: #2e7d32; }
	.creation-desc-box.linggen-frame-super-negative { border-color: #c62828; animation: demonic-flicker 3s infinite linear; }
	.creation-desc-box.linggen-frame-rare { border-color: #4fc3f7; }
	.creation-desc-box.linggen-frame-epic { border-image: linear-gradient(60deg, #ba68c8, #f06292, #ffd54f, #81c784, #4fc3f7, #7986cb) 1; }
	.creation-desc-box.linggen-frame-legendary { border-color: #ffd700; }

	/* --- Các thành phần chung khác (Tiêu đề, v.v.) --- */
	.linggen-frame-header { display: flex; align-items: center; gap: 20px; margin-bottom: 15px; padding-bottom: 10px; border-bottom: 1px dashed rgba(255, 255, 255, 0.2); }
	.linggen-frame-header h4 { margin: 0; flex-grow: 1; font-size: 1.5em; font-family: 'ZCOOL XiaoWei', serif; }
