	.linggen-frame-super-negative .linggen-frame-header h4 { color: #ff8a80; text-shadow: 0 0 10px #c62828; }
	.linggen-frame-rare .linggen-frame-header h4 { color: #4fc3f7; text-shadow: 0 0 10px #039be5; }
	.linggen-frame-epic .linggen-frame-header h4 { color: white; text-shadow: 0 0 5px black; }
	.linggen-frame-legendary .linggen-frame-header h4 { color: #ffd700; text-shadow: 0 0 10px #ffc107; }

