        async function getLorebookEntries(lorebookName) {
            if (window.parent?.TavernHelper?.getLorebookEntries) {
                try {
                    return await window.parent.TavernHelper.getLorebookEntries(lorebookName);
                } catch (e) {
                    console.error("Lỗi khi gọi getLorebookEntries:", e);
                    return [];
                }
            }
            console.warn("Không tìm thấy API Lorebook (getLorebookEntries).");
            return [];
        }

        async function setLorebookEntries(lorebookName, entriesToUpdate) {
            if (window.parent?.TavernHelper?.setLorebookEntries) {
                try {
                    await window.parent.TavernHelper.setLorebookEntries(lorebookName, entriesToUpdate);
                } catch (e) {
                    console.error("Lỗi khi gọi setLorebookEntries:", e);
                }
            } else {
                console.warn("Không tìm thấy API Lorebook (setLorebookEntries).");
            }
        }
        // THÊM MỚI: Hàm quản lý entry Lorebook, đã được tùy chỉnh cho bảng điều khiển này
        async function manageLorebookEntries() {
            // Thoát sớm nếu không có API Lorebook hoặc chưa có lưu trữ nào được tải
            if (!window.parent?.TavernHelper?.getLorebookEntries || !currentArchiveName) return;

            try {
                const lorebookName = 'PNTT 8.2-VN';
                const entries = await getLorebookEntries(lorebookName);
                if (!entries || entries.length === 0) return;

                // Lấy các dữ liệu cần thiết để kiểm tra điều kiện
                const playerTraits = (currentPlayerData.playerTraits || []).map(t => t.name);
                const hasAnySystemTrait = playerTraits.some(t => t.includes('Hệ Thống'));

                // Lấy số lượng log hiện tại từ cơ sở dữ liệu
                const archive = await db.archives.get(currentArchiveName);
                const logs = archive?.data?.logs || [];
                // Nếu số log > 1, nghĩa là người chơi đã qua lượt đầu tiên (lượt 1 là log "Thiên Đạo Khai Mở")
                const isPastFirstTurn = logs.length > 1;

                const updatedEntries = [];

                entries.forEach(entry => {
                    const comment = (entry.comment || '').trim();

                    // --- LOGIC 1: Entry "Thức Tỉnh" (chỉ kích hoạt ở lượt đầu tiên) ---
                    if (comment === "📓⚙️THỨC TỈNH HỆ THỐNG") {
                        const shouldBeEnabled = hasAnySystemTrait && !isPastFirstTurn;

                        if (entry.enabled !== shouldBeEnabled) {
                            updatedEntries.push({ uid: entry.uid, enabled: shouldBeEnabled });
                        }
                        return; // Xử lý xong, chuyển sang entry tiếp theo
                    }

                    // --- Logic 2 - Entry "Vận Hành" (kích hoạt MỌI LÚC) ---
                    else if (comment === "📓⚙️VẬN HÀNH HỆ THỐNG") {
                        // Điều kiện rất đơn giản: chỉ cần có thiên phú hệ thống là được
                        const shouldBeEnabled = hasAnySystemTrait;

                        if (entry.enabled !== shouldBeEnabled) {
                            updatedEntries.push({ uid: entry.uid, enabled: shouldBeEnabled });
                        }
                        return; // Xử lý xong, chuyển sang entry tiếp theo
                    }

                    // --- LOGIC 3: Áp dụng cho các entry hệ thống cụ thể khác ---
                    else if (comment.toLowerCase().startsWith('tên hệ thống-')) {
                        const systemName = comment.substring('Tên Hệ Thống-'.length).trim();
                        const shouldBeEnabled = playerTraits.includes(systemName);

                        if (entry.enabled !== shouldBeEnabled) {
                            updatedEntries.push({ uid: entry.uid, enabled: shouldBeEnabled });
                        }
                    }
                });

                // Nếu có bất kỳ entry nào cần thay đổi trạng thái, gửi yêu cầu cập nhật
                if (updatedEntries.length > 0) {
                    await setLorebookEntries(lorebookName, updatedEntries);
                    console.log('%cLorebook đã được đồng bộ hóa (bao gồm logic thức tỉnh và vận hành). Các thay đổi:', 'color: lightgreen; font-weight: bold;', updatedEntries);
                }
            } catch (error) {
                console.warn('Quản lý Lorebook thất bại:', error);
            }
        }

		async function handleLorebookToggle(mode) {
			let lorebookName = 'DLC Phàm Nhân Tu Tiên'; // Tên lorebook mặc định

			// Vòng lặp để thử lại nếu không tìm thấy lorebook
			while (true) {
				const entries = await getLorebookEntries(lorebookName);

				if (!entries || entries.length === 0) {
					const newName = await showCustomPrompt(
						`Không tìm thấy Lorebook "${lorebookName}" hoặc Lorebook này trống.\n\nVui lòng nhập đúng tên Lorebook bạn muốn thao tác:`,
						lorebookName,
						'Lỗi Lorebook'
					);

					if (!newName) { // Người dùng nhấn Hủy
						return; 
					}
					lorebookName = newName; // Thử lại với tên mới
					continue; // Quay lại đầu vòng lặp
				}

				// Nếu tìm thấy, bắt đầu xử lý
				const entriesToUpdate = [];
				const enablePrefix = mode === 'goc' ? '[Gốc]' : '[CMT]';
				const disablePrefix = mode === 'goc' ? '[CMT]' : '[Gốc]';

				entries.forEach(entry => {
					const comment = (entry.comment || '').trim();

					if (comment.startsWith(enablePrefix) && !entry.enabled) {
						entriesToUpdate.push({ uid: entry.uid, enabled: true });
					} else if (comment.startsWith(disablePrefix) && entry.enabled) {
						entriesToUpdate.push({ uid: entry.uid, enabled: false });
					}
				});

				if (entriesToUpdate.length > 0) {
					await setLorebookEntries(lorebookName, entriesToUpdate);
					await showCustomAlert(`Đã cập nhật ${entriesToUpdate.length} entry trong Lorebook "${lorebookName}" theo chế độ [${mode.toUpperCase()}]!`);
				} else {
					await showCustomAlert(`Không có entry nào cần cập nhật. Trạng thái Lorebook "${lorebookName}" đã đúng theo chế độ bạn chọn.`);
				}

				document.getElementById('original-work-mode-overlay').classList.remove('visible');
				break; // Thoát khỏi vòng lặp sau khi thành công
			}
		}

