        function sanitizeHTML(htmlString) {
            let sanitized = String(htmlString).replace(/<script\b[^>]*>([\s\S]*?)<\/script>/gi, '');
            sanitized = sanitized.replace(/\s(on\w+)=["'][^"']*["']/gi, '');
            return sanitized;
        }

        function enforceRenderLimit() {
            const limit = regexConfig.renderLimit || 100;
            const messages = mainContentArea.querySelectorAll('.log-entry');
            if (messages.length > limit) {
                const toRemove = messages.length - limit;
                for(let i = 0; i < toRemove; i++) {
                    messages[i].remove();
                }
            }
        }

        function createLogEntryElement(logData, type) {
            const isSummary = (typeof logData !== 'string' && (logData.content.startsWith('[Thiên Đạo Tổng Kết:') || logData.content.includes('<h4>Thiên Đạo Khai Mở</h4>')));
            const logEntry = document.createElement('div');
            logEntry.classList.add('log-entry', type);
            if (isSummary) {
                logEntry.classList.add('summary');
            }
            const content = (typeof logData === 'string') ? logData : logData.content;
            const id = (typeof logData === 'string') ? null : logData.id;
            if (id) {
                logEntry.dataset.logId = id;
            }
            logEntry.innerHTML = sanitizeHTML(content);
            return logEntry;
        }

        function addMessageToLog(logData, type) {
			const logEntry = createLogEntryElement(logData, type);
			mainContentArea.appendChild(logEntry);
			enforceRenderLimit();
			return logEntry;
        }

        function parseRemarksString(str) {
            return (str || '').split('|').reduce((acc, part) => {
                const firstColonIndex = part.indexOf(':');
                if (firstColonIndex > -1) {
                    const key = part.substring(0, firstColonIndex).trim();
                    const value = part.substring(firstColonIndex + 1).trim();
                    if (key) acc[key] = value;
                }
                return acc;
            }, {});
        }

        function serializeRemarksObject(remarksObj) {
            return Object.entries(remarksObj)
                .filter(([key, value]) => value !== undefined && value !== null)
                .map(([key, value]) => `${key}:${value}`)
                .join('|');
        }

		<!-- THÊM MỚI MOD: Di chuyển phần trang bị để áp dụng cho mọi nhân vật -->
        function serializeCharacterRemarks(char, forAI = false) {
            const remarks = {
                'Tuổi': char.age,
                'Thọ Nguyên': char.shouyuan,
            };

			<!-- Chuyển ra đầy -->
			remarks['equipment'] = JSON.stringify({
				weapon: char.weapon,
				armor: char.armor,
				technique: char.technique,
				treasure: char.treasure,
			});<!-- Kết thúc -->
            if (char.id === 'B1') {
                remarks['Linh Căn'] = char.linggen;
                remarks['Linh Thạch'] = char.spiritStones;
				remarks['Giá Trị Thiện Ác'] = char.shanE;
                remarks['Tiến Độ Tu Vi'] = `${char.progress}%`;
                remarks['hp'] = `${char.hp.current}/${char.hp.max}`;
                remarks['traits'] = JSON.stringify(char.playerTraits);
                remarks['avatar'] = char.avatarAppearance;
                if (!forAI) {
					<!-- Lấy từ đây -->
                    remarks['isExtreme'] = char.isExtreme;
                    remarks['warehouse'] = JSON.stringify(char.warehouse);
                    remarks['deathCount'] = char.deathCount;
                }
            } else {
                 remarks['equipment'] = JSON.stringify({
                    weapon: char.weapon,
                    armor: char.armor,
                    technique: char.technique,
                    treasure: char.treasure,
                });
                 remarks['inventory'] = JSON.stringify(char.inventoryItems);
            }

            if (char.isBonded) {
                remarks['isBonded'] = 'true';
            }
            if (char.deeds) {
                remarks['deeds'] = char.deeds;
            }

            return serializeRemarksObject(remarks);
        }

        function getTableIndexFromId(id) {
            if (!id) return null;
            const prefix = id.charAt(0);
            switch(prefix) {
                case 'B':
                case 'C':
                case 'G':
                    return '0'; // Characters
				case 'X':
					return '10'; // System (Thêm mới MOD)
                case 'I':
                    return '1'; // Inventory
                case 'E':
                    return '9'; // Equipment
                case 'T':
                    return '6'; // Tasks
                case 'S':
                    return '8'; // Skills
                case 'W': // World Events
                    return '5';
                case 'P': // Spirit Beasts
                    return '7';
                default:
                    return null;
            }
        }

		<!-- THÊM MỚI MOD: Thêm cột 6 Phẩm Chất -->
        function applyChanges(baseState, delta) {
            const newState = JSON.parse(JSON.stringify(baseState));

            delta.forEach(op => {
                try {
                    const { command, id, data, eventData, attribute, value, slot, item, locationData, regionData, locationId } = op;

                    if (command === 'add' && id === TIME_LOCATION_ROW_ID) {
                        const timeRow = (newState['4'] || []).find(row => row.id === TIME_LOCATION_ROW_ID) || newState['4'][0];
                        if (timeRow) {
                            Object.assign(timeRow, data);
                        }
                        return;
                    }

                    if (command === 'createLocation') {
                        if (locationData.type === 'poi') {
                            WORLD_MAP_DATA.points_of_interest.push(locationData.data);
                        } else if (locationData.type === 'sub_region') {
                            WORLD_MAP_DATA.sub_regions.push(locationData.data);
                        } else if (locationData.type === 'main_region') {
                            WORLD_MAP_DATA.main_regions.push(locationData.data);
                        }
                        return;
                    }

                    if (command === 'updateRegion') {
                        const regionToUpdate = WORLD_MAP_DATA.main_regions.find(r => r.name === regionData.name) || WORLD_MAP_DATA.sub_regions.find(r => r.name === regionData.name);
                        if (regionToUpdate) {
                            regionToUpdate.points = regionData.points;
                        }
                        return;
                    }

                    if (command === 'deleteLocation') {
                        WORLD_MAP_DATA.points_of_interest = WORLD_MAP_DATA.points_of_interest.filter(p => p.name !== locationId);
                        return;
                    }

                    const tableIndex = getTableIndexFromId(id || data?.['0']);

                    if (tableIndex === null && command !== 'addWorldEvent') {
                        console.error("Không thể xác định chỉ mục bảng từ ID:", op);
                        return;
                    }

                    if (!newState[tableIndex]) newState[tableIndex] = {};

					switch (command) {
						case 'set':
							if (data['9']) {
								let remarksObj;
								// 1. Nếu ghi chú là một chuỗi, hãy thử phân tích nó thành một đối tượng
								if (typeof data['9'] === 'string') {
									try {
										// Thay thế dấu nháy đơn mà AI có thể sử dụng bằng dấu nháy kép tiêu chuẩn để biến nó thành JSON hợp lệ
										const jsonString = data['9'].replace(/'/g, '"');
										remarksObj = JSON.parse(jsonString);
									} catch (e) {
										// Nếu phân tích dưới dạng JSON không thành công, hãy thử phân tích theo định dạng key:value|...
										console.warn("Phân tích ghi chú dưới dạng JSON không thành công, quay lại định dạng phân tách bằng dấu gạch đứng.", e);
										remarksObj = parseRemarksString(data['9']);
									}
								} else {
									// Nếu đã là một đối tượng, hãy sử dụng trực tiếp
									remarksObj = data['9'];
								}

								// 2. Phân tích đệ quy các chuỗi JSON có thể tồn tại bên trong (ví dụ: giá trị của inventory)
								remarksObj = recursivelyParseJsonStrings(remarksObj);

								// 3. Xử lý kho đồ từ đối tượng ghi chú đã được phân tích
								if (remarksObj.inventory && Array.isArray(remarksObj.inventory)) {
									remarksObj.inventory.forEach(itemRow => {
										const itemId = itemRow.id || itemRow['0'];
										if (itemId && !newState['1'][itemId]) {
											newState['1'][itemId] = {
												"0": itemId,
												"1": itemRow.name || itemRow['1'],
												"2": itemRow.type || itemRow['2'],
												"3": itemRow.description || itemRow['3'],
												"4": itemRow.effect || itemRow['4'],
												"5": (itemRow.quantity || itemRow['5'] || '1').toString(),
												"6": itemRow.quality || itemRow['6'] || "Không rõ", <!-- Dòng mới -->
											};
										}
									});
									// Đảm bảo trường inventory ở định dạng chuỗi trước khi được tuần tự hóa trở lại vào ghi chú
									remarksObj.inventory = JSON.stringify(remarksObj.inventory);
								}

								// 4. Tuần tự hóa đối tượng ghi chú đã được xử lý hoàn toàn thành định dạng chuỗi cuối cùng
								data['9'] = serializeRemarksObject(remarksObj);
							}

							// Xử lý trường thuộc tính '11' (giữ nguyên)
							if (data['11'] && typeof data['11'] === 'object') {
								data['11'] = JSON.stringify(data['11']);
							} else if (typeof data['11'] === 'string') {
								// Thêm tính năng mạnh mẽ: xử lý trường hợp thuộc tính cũng là chuỗi có dấu nháy đơn
								try {
