        function extractCommands(text) {
            const commands = [];
            const commandRegex = /(add|set|de|addWorldEvent|addSmallSummary|addLargeSummary|updateAttribute|equipItem|unequipItem|createLocation|updateRegion|deleteLocation)\s*\(/g;
            let match;

            while ((match = commandRegex.exec(text)) !== null) {
                const commandName = match[1];
                const startIndex = match.index + commandName.length;
                let openParens = 0;
                let endIndex = -1;

                for (let i = startIndex; i < text.length; i++) {
                    if (text[i] === '(') {
                        openParens++;
                    } else if (text[i] === ')') {
                        openParens--;
                        if (openParens === 0) {
                            endIndex = i;
                            break;
                        }
                    }
                }

                if (endIndex !== -1) {
                    const fullCommand = text.substring(match.index, endIndex + 1);
                    commands.push(fullCommand);
                    commandRegex.lastIndex = endIndex;
                }
            }
            return commands;
        }

		function recursivelyParseJsonStrings(data) {
			// 1. Nếu dữ liệu hiện tại là một chuỗi, thì thử phân tích
			if (typeof data === 'string') {
				const trimmedString = data.trim();
				// 2. Kiểm tra xem chuỗi có giống như một đối tượng hoặc một mảng không
				if ((trimmedString.startsWith('{') && trimmedString.endsWith('}')) || (trimmedString.startsWith('[') && trimmedString.endsWith(']'))) {
					try {
						const validJsonString = trimmedString.replace(/'/g, '"');
						// 4. Sử dụng chuỗi đã được sửa để phân tích
						const parsedData = JSON.parse(validJsonString);
						// 5. Gọi đệ quy cho dữ liệu vừa được phân tích để xử lý các tầng lồng nhau
						return recursivelyParseJsonStrings(parsedData);
					} catch (e) {
						// Nếu sau khi thay thế dấu nháy đơn vẫn phân tích thất bại, có nghĩa là định dạng thực sự có vấn đề, trả về chuỗi gốc để tránh mất dữ liệu
						console.warn(`recursivelyParseJsonStrings ngay cả sau khi sửa dấu nháy đơn vẫn phân tích thất bại:`, data, e);
						return data;
					}
				}
			}
			// 6. Nếu dữ liệu là một mảng, thì duyệt qua từng phần tử và gọi đệ quy
			else if (Array.isArray(data)) {
				return data.map(item => recursivelyParseJsonStrings(item));
			}
			// 7. Nếu dữ liệu là một đối tượng, thì duyệt qua từng giá trị thuộc tính và gọi đệ quy
			else if (typeof data === 'object' && data !== null) {
				for (const key in data) {
					if (Object.hasOwnProperty.call(data, key)) {
						data[key] = recursivelyParseJsonStrings(data[key]);
					}
				}
			}
			// 8. Nếu là các kiểu dữ liệu khác (số, boolean, v.v.) hoặc phân tích thất bại, trả về trực tiếp
			return data;
		}
        function parseTableEditCommands(commandsString, errorMessages = []) {
            const delta = [];
            let smallSummary = null;
            let largeSummary = null;

            const commands = extractCommands(commandsString);

            commands.forEach(commandStr => {
                const match = commandStr.match(/^(\w+)\(([\s\S]*)\)$/);
				if (!match) {
					errorMessages.push({
						title: "Lỗi định dạng cơ bản của lệnh",
						details: `Không thể phân tích lệnh "${commandStr}" vì nó thiếu cấu trúc "command(...)" hợp lệ.`
					});
					return;
				}

                const command = match[1];
                const argsString = match[2];

                try {
                    let id, data, attribute, value, slot, item;
                    switch(command) {
                        case 'addSmallSummary':
                            smallSummary = JSON.parse(argsString);
                            break;
                        case 'addLargeSummary':
                            largeSummary = JSON.parse(argsString);
                            break;
                        case 'addWorldEvent':
                            const eventArgs = JSON.parse(`[${argsString}]`);
                            delta.push({ command: 'addWorldEvent', eventData: { "0": eventArgs[0], "1": eventArgs[1], "2": eventArgs[2], "id": `W${crypto.randomUUID()}` } });
                            showDanmaku('Ký sự đại sự thế giới cập nhật', 'world');
                            break;
                        case 'createLocation':
                            const locArgs = JSON.parse(argsString);
                            delta.push({ command: 'createLocation', locationData: locArgs });
                            break;
                        case 'updateRegion':
                            const regionArgs = JSON.parse(argsString);
                            delta.push({ command: 'updateRegion', regionData: regionArgs });
                            break;
                        case 'deleteLocation':
                            const locId = JSON.parse(argsString);
                            delta.push({ command: 'deleteLocation', locationId: locId });
                            break;
                        case 'set':
                            data = JSON.parse(argsString);
							data = recursivelyParseJsonStrings(data);
                            delta.push({ command, data });
                            id = data['0'];
                            if(id.startsWith('C')) {
                                updatedCharacterIds.add(id);
                                showDanmaku(`Nhân vật mới ${data['1'].split('|')[0]} xuất hiện`, 'npc');
                            } else if (id.startsWith('I')) {
                                showDanmaku(`Thu được vật phẩm mới: ${data['1']}`, 'item');
                            } else {
                                showDanmaku('Thế giới đã có một số thay đổi', 'world');
                            }
                            break;
                        case 'updateAttribute':
                            const attrArgs = JSON.parse(`[${argsString}]`);
                            id = attrArgs[0];
                            attribute = attrArgs[1];
                            value = attrArgs[2];
                            delta.push({ command, id, attribute, value });
                            if(id.startsWith('C') || id.startsWith('G')) updatedCharacterIds.add(id);
                            break;
                        case 'add':
                            const firstCommaIndex = argsString.indexOf(',');
							if (firstCommaIndex === -1) throw new Error("Lệnh add thiếu dấu phẩy để phân tách.");
                            id = JSON.parse(argsString.substring(0, firstCommaIndex));
                            const dataString = argsString.substring(firstCommaIndex + 1).trim();
                            data = JSON.parse(dataString);
							data = recursivelyParseJsonStrings(data);
                            delta.push({ command, id, data });
                            if(id.startsWith('C') || id.startsWith('G')) {
                                updatedCharacterIds.add(id);
                                const char = characterDatabase[id];
                                const name = char ? char.name : 'Một người nào đó';
                                showDanmaku(`Trạng thái của ${name} đã thay đổi`, 'npc');
                            } else if (id === 'B1') {
                                showDanmaku('Trạng thái người chơi đã thay đổi', 'player');
                            } else {
                                showDanmaku('Thế giới đã có một số thay đổi', 'world');
                            }
                            break;
                        case 'de':
                            id = JSON.parse(argsString);
                            delta.push({ command, id });
                            if(id.startsWith('C')) updatedCharacterIds.add(id);
                            if(id.startsWith('I')) {
                                const item = inventoryItems.find(i => i.id === id);
                                showDanmaku(`Mất vật phẩm: ${item ? item.name : ''}`, 'item');
                            } else {
                                showDanmaku('Thế giới đã có một số thay đổi', 'world');
                            }
                            break;
                        case 'equipItem':
                        case 'unequipItem':
                            const equipArgs = JSON.parse(`[${argsString}]`);
                            id = equipArgs[0];
                            slot = equipArgs[1];
                            item = equipArgs[2];
                            delta.push({ command, id, slot, item });
                            break;
                    }
                } catch (e) {
					errorMessages.push({
						title: `Lỗi định dạng tham số của lệnh "${command}"`,
						details: `Xảy ra lỗi khi phân tích lệnh "${commandStr}".\nThông tin lỗi: ${e.message}\n\nĐiều này thường xảy ra khi các tham số trong ngoặc không phải định dạng JSON hợp lệ, hoặc số lượng/kiểu tham số không đúng.`
					});					
                }
            });

            if (updatedCharacterIds.size > 0) {
                const btn = document.getElementById('surrounding-characters-button');
                if (!btn.querySelector('.red-dot')) {
                    const dot = document.createElement('span');
                    dot.className = 'red-dot';
                    btn.appendChild(dot);
                }
            }
            return { delta, smallSummary, largeSummary };
        }

