		function openInventoryViewer() {			
			const overlay = document.getElementById('inventory-viewer-overlay');
			overlay.classList.add('visible');

			if (inventorySelectionMode !== 'none') {
				exitSelectionMode();
			}

			const CATEGORIES = {
				'Tất Cả': [],
				'Công Pháp': ['Công Pháp'],
				'Trang Bị': ['Vũ Khí', 'Hộ Giáp', 'Pháp Bảo'],
				'Vật Phẩm Tiêu Hao': ['Vật Phẩm Tiêu Hao', 'Đan Dược', 'Phù Lục'],
				'Nguyên Liệu': ['Nguyên Liệu'],
				'Vật Phẩm Quan Trọng': ['Vật Phẩm Quan Trọng'],
				'Vật Phẩm Khác': ['Vật Phẩm Khác']
			};

			let activeMainCat = 'Tất Cả';
			let activeSubCat = 'Tất Cả';

			const mainCatsContainer = document.getElementById('inventory-viewer-main-cats');
			const subCatsContainer = document.getElementById('inventory-viewer-sub-cats');
			const searchInput = document.getElementById('inventory-search-input');

			function renderItems() {
				const grid = document.getElementById('inventory-viewer-grid');
				grid.innerHTML = '';
				const searchTerm = searchInput.value.toLowerCase();

				let itemsToDisplay = [...inventoryItems];
				if (activeMainCat !== 'Tất Cả' && CATEGORIES[activeMainCat]) { itemsToDisplay = itemsToDisplay.filter(item => CATEGORIES[activeMainCat].includes(item.type)); }
				if (activeSubCat !== 'Tất Cả') { itemsToDisplay = itemsToDisplay.filter(item => item.type === activeSubCat); }
				if (searchTerm) { itemsToDisplay = itemsToDisplay.filter(item => item.name.toLowerCase().includes(searchTerm)); }

				itemsToDisplay.forEach(item => {
					const slot = document.createElement('div');
					slot.className = `inventory-viewer-slot ${itemsToDelete[item.id] ? 'selected' : ''}`;
					slot.dataset.itemId = item.id;
					slot.dataset.itemName = item.name;
					slot.dataset.itemQuantity = item.quantity;
					slot.dataset.itemQuality = item.quality;

					const iconClass = itemIconMap[item.type] || itemIconMap['Mặc Định'];
					slot.innerHTML = `
						<i class="fas ${iconClass} inventory-slot-icon"></i>
						<span class="inventory-slot-name">${item.name}</span>
						<span class="inventory-slot-quantity">${item.quantity}</span>
						<span class="item-quality">[${item.quality || 'Phàm Phẩm'}]</span>
						<div class="delete-quantity-input-container">
							<input type="number" min="1" max="${item.quantity}" value="${itemsToDelete[item.id] || 1}" class="delete-quantity-input">
						</div>
					`;

					const quantityInput = slot.querySelector('.delete-quantity-input');

					// Ngăn sự kiện click từ input lan ra ngoài slot
					quantityInput.addEventListener('click', e => e.stopPropagation()); 

					quantityInput.addEventListener('input', () => {
						let val = parseInt(quantityInput.value);
						const max = parseInt(quantityInput.max);
						if (isNaN(val) || val < 1) val = 1;
						if (val > max) val = max;
						quantityInput.value = val; // Chuẩn hóa giá trị
						if (itemsToDelete[item.id]) {
							itemsToDelete[item.id] = val;
						}
					});

					slot.addEventListener('click', () => {
						if (inventorySelectionMode === 'copy') {
							slot.classList.toggle('selected');
						} else if (inventorySelectionMode === 'delete') {
							slot.classList.toggle('selected');
							if (slot.classList.contains('selected')) {
								itemsToDelete[item.id] = parseInt(quantityInput.value);
							} else {
								delete itemsToDelete[item.id];
							}
						} else {
							showItemDetail(item);
						}
					});
					grid.appendChild(slot);
				});
			}

			function renderSubCats() {
				subCatsContainer.innerHTML = '';
				const subCats = CATEGORIES[activeMainCat];
				if (subCats && subCats.length > 1) { // Chỉ hiển thị nếu có nhiều hơn 1 danh mục con
					const allBtn = document.createElement('button');
					allBtn.className = 'inv-cat-btn active';
					allBtn.textContent = 'Tất Cả';
					allBtn.onclick = () => {
						activeSubCat = 'Tất Cả';
						subCatsContainer.querySelector('.active').classList.remove('active');
						allBtn.classList.add('active');
						renderItems();
					};
					subCatsContainer.appendChild(allBtn);

					subCats.forEach(catName => {
						const btn = document.createElement('button');
						btn.className = 'inv-cat-btn';
						btn.textContent = catName;
						btn.onclick = () => {
							activeSubCat = catName;
							subCatsContainer.querySelector('.active').classList.remove('active');
							btn.classList.add('active');
							renderItems();
						};
						subCatsContainer.appendChild(btn);
					});
				}
			}

			function renderMainCats() {
				mainCatsContainer.innerHTML = '';
				Object.keys(CATEGORIES).forEach(catName => {
					const btn = document.createElement('button');
					btn.className = `inv-cat-btn ${catName === activeMainCat ? 'active' : ''}`;
					btn.textContent = catName;
					btn.onclick = () => {
						activeMainCat = catName;
						activeSubCat = 'Tất Cả'; // Reset danh mục con khi đổi danh mục chính
						mainCatsContainer.querySelector('.active').classList.remove('active');
						btn.classList.add('active');
						renderSubCats();
						renderItems();
					};
					mainCatsContainer.appendChild(btn);
				});
			}

			searchInput.oninput = renderItems;
			renderMainCats();
			renderSubCats();
			renderItems();
		}

		// Batch Delete & Shared Controls Feature
		function enterSelectionMode(mode) {
			inventorySelectionMode = mode;
			const overlay = document.getElementById('inventory-viewer-overlay');
			overlay.classList.add(`selection-mode-${mode}`);

			document.getElementById('inventory-initial-actions').classList.add('hidden');
			document.getElementById('inventory-selection-controls').classList.remove('hidden');

			if (mode === 'copy') {
				showCustomAlert('Hãy chọn những vật phẩm muốn sao chép thông tin, sau khi xong thì nhấn nút tick.');
			} else if (mode === 'delete') {
				itemsToDelete = {}; // Reset danh sách xóa
				showCustomAlert('Hãy chọn những vật phẩm muốn xóa và nhập số lượng, sau khi xong thì nhấn nút tick.');
			}
		}

		function exitSelectionMode() {
			const overlay = document.getElementById('inventory-viewer-overlay');
			overlay.classList.remove('selection-mode-copy', 'selection-mode-delete');
			overlay.querySelectorAll('.selected').forEach(el => el.classList.remove('selected'));

			document.getElementById('inventory-initial-actions').classList.remove('hidden');
			document.getElementById('inventory-selection-controls').classList.add('hidden');

			inventorySelectionMode = 'none';
			itemsToDelete = {};
			// render lại để xóa các ô nhập số lượng
			if(overlay.classList.contains('visible')) {
				openInventoryViewer();
			}
		}

		async function handleConfirmSelection() {
			if (inventorySelectionMode === 'copy') {
				const selectedSlots = document.querySelectorAll('#inventory-viewer-overlay .inventory-viewer-slot.selected');
				if (selectedSlots.length === 0) {
					 await showCustomAlert('Chưa có vật phẩm nào được chọn.');
				} else {
					const infoArray = Array.from(selectedSlots).map(slot => `x${slot.dataset.itemQuantity} ${slot.dataset.itemName}(${slot.dataset.itemQuality || 'Phàm Phẩm'})`);
					await navigator.clipboard.writeText(`[${infoArray.join(', ')}]`);
					await showCustomAlert('Thông tin vật phẩm đã được sao chép!');
				}
			} else if (inventorySelectionMode === 'delete') {
				const items = Object.keys(itemsToDelete);
				if (items.length === 0) {
					// Nếu không chọn gì thì coi như hủy
					exitSelectionMode();
					return;
				}

				let confirmationText = 'Bạn có chắc chắn muốn xóa các vật phẩm sau không?\n\n';
				items.forEach(itemId => {
					const item = inventoryItems.find(i => i.id === itemId);
					if (item) {
						confirmationText += `- ${itemsToDelete[itemId]} x ${item.name}\n`;
					}
				});

				if (await showCustomConfirm(confirmationText)) {
					let deletedCount = 0;
					for (const itemId in itemsToDelete) {
						const itemInState = currentState['1'][itemId];
						if (itemInState) {
							const quantityToDelete = itemsToDelete[itemId];
							const currentQuantity = parseInt(itemInState['5']);
							if (quantityToDelete >= currentQuantity) {
								delete currentState['1'][itemId];
							} else {
								itemInState['5'] = (currentQuantity - quantityToDelete).toString();
							}
							deletedCount++;
						}
					}

					if (deletedCount > 0) {
						await saveCurrentState();
						syncStateFromTables();
						await showCustomAlert('Các vật phẩm đã chọn đã được xóa.');
					}
				}
			}

			// Luôn thoát chế độ lựa chọn sau khi xác nhận
			exitSelectionMode();
		}
