		function addAction(type, data, context = {}, preformattedText = null, isHidden = false) {
			let actionText = preformattedText; // Ưu tiên văn bản được định dạng sẵn

			if (actionText === null) {
				// Nếu không có văn bản định dạng sẵn, dùng logic switch cũ
				switch(type) {
					case 'use':
						const existingAction = actionQueue.find(a => a.type === 'use' && a.item.name === data.name);
						if (existingAction) {
							existingAction.quantity++;
							renderActionQueue();
							closeItemDetail();
							return;
						}
						actionText = `Sử dụng ${data.name}`;
						break;
					case 'travel':
						actionText = `Người chơi đi đến ${data.location}, cách ${data.distance} km`;
						break;
					case 'communicate':
						actionText = `Nói với ${context.charName}: "${data}"`;
						break;
					case 'gift':
						actionText = `Tặng [${data.name}] cho ${context.charName}`;
						break;
					case 'spar':
						actionText = `Yêu cầu tỉ thí với ${context.charName}`;
						break;
					case 'accompany':
						actionText = `Mời ${context.charName} đồng hành cùng ngươi`;
						break;
					case 'cultivate':
						actionText = `Mời ${context.charName} song tu`;
						break;
					case 'alchemy':
						actionText = `Người chơi sử dụng [${data.map(i => i.name).join(', ')}] để luyện đan, luyện ra một viên đan dược cấp ${context.tier}`;
						break;
					case 'refining':
						actionText = `Người chơi sử dụng [${data.map(i => i.name).join(', ')}] để bắt đầu luyện khí`;
						break;
					default:
						// Nếu một type không xác định được truyền vào, sẽ hiển thị lỗi thay vì dòng trống
						actionText = `[Lỗi] Hành động không xác định: ${type}`;
				}
			}

			if(type === 'travel') {
				 actionQueue = actionQueue.filter(a => a.type !== 'travel');
			}

			// Thêm thuộc tính isHidden vào đối tượng action
			actionQueue.push({ type, text: actionText, data: data, context: context, isHidden: isHidden }); <!-- CHỈNH LẠI -->

			renderActionQueue();

			if(type === 'use') closeItemDetail();
			if(type === 'travel') {
				worldMapOverlay.classList.remove('visible');
			}
		}

