                        const entriesToUpdate = entries
                            .filter(entry => entry.comment && entry.comment.startsWith('COT') && entry.enabled !== targetEnabledState)
                            .map(entry => ({ uid: entry.uid, enabled: targetEnabledState }));

                        if (entriesToUpdate.length > 0) {
                            await setLorebookEntries(lorebookName, entriesToUpdate);
                            await showCustomAlert(`Đã điều chỉnh lại tương ứng. Chúc bạn chơi vui vẻ!`);
                        }
                    } else {
                        console.warn("Không tìm thấy API Lorebook để cấu hình các mục 'COT'.");
                    }
                }
            } catch (error) {
                console.error("Lỗi trong quá trình kiểm tra preset:", error);
            } finally {
                // Đánh dấu là đã kiểm tra để không hỏi lại lần sau
                // localStorage.setItem('DECAL_PRESET_CHECK_DONE', 'true');
            }
        }	
	function getForcefulCommandPrefix() {
		const randomIndex = Math.floor(Math.random() * COMMAND_PREFIXES.length);
		return COMMAND_PREFIXES[randomIndex];
	}	

	/**
	 * Phân tích JSON một cách an toàn, xử lý cả trường hợp dữ liệu đã là object hoặc là một chuỗi JSON.
	 * @param {*} data Dữ liệu cần phân tích.
	 * @param {*} defaultValue Giá trị trả về mặc định nếu phân tích thất bại.
	 * @returns {object|array} Đối tượng hoặc mảng đã được phân tích.
	 */
	function robustJSONParse(data, defaultValue = {}) {
		// Nếu dữ liệu không tồn tại hoặc rỗng, trả về mặc định
		if (!data) {
			return defaultValue;
		}
		// Nếu dữ liệu đã là một đối tượng, trả về chính nó
		if (typeof data === 'object') {
			return data;
		}
		// Nếu dữ liệu là một chuỗi, thử phân tích nó
		if (typeof data === 'string') {
			try {
				return JSON.parse(data);
			} catch (e) {
				console.error("Lỗi khi phân tích chuỗi JSON:", data, e);
				return defaultValue; // Trả về mặc định nếu chuỗi không hợp lệ
			}
		}
		// Trả về mặc định cho các trường hợp khác
		return defaultValue;
	}		
	function parseSystemData(row) {
		if (!row) return null;

		const functions = robustJSONParse(row['5'], []);
		const resources = robustJSONParse(row['6'], {});
		const store = robustJSONParse(row['7'], { date: '', items: [] });
		const upgradeInfoRaw = robustJSONParse(row['8'], {});

		const gachaData = {
			event_pool: robustJSONParse(row['10'], null)
		};

		const upgradeInfo = {
			level: upgradeInfoRaw.level || 1,
			conditions: upgradeInfoRaw.conditions || '',
			new_functions: upgradeInfoRaw.new_functions || [],
			rewards: upgradeInfoRaw.rewards || '',
			isUpdating: upgradeInfoRaw.isUpdating || false,
			progress: upgradeInfoRaw.progress || 0
		};

		// Logic mới này sẽ tách chuỗi tại dấu hai chấm (:) đầu tiên, lấy ra chính xác key và value
		const dungeonStatus = (row['12'] || '').split('|').reduce((acc, part) => {
			const separatorIndex = part.indexOf(':');
			if (separatorIndex > -1) {
				const key = part.substring(0, separatorIndex).trim();
				const value = part.substring(separatorIndex + 1);

				// Chỉ xử lý các key hợp lệ để tránh lỗi
				const validKeys = ['isInDungeon', 'dungeonInfo', 'lastEntryDate', 'specialDungeonData'];
				if (validKeys.includes(key)) {
					if (key === 'isInDungeon') {
						acc[key] = (value === 'true');
					} else {
						acc[key] = value;
					}
				}
			}
			return acc;
		}, { isInDungeon: false, dungeonInfo: '', lastEntryDate: '', specialDungeonData: '' });


		return {
			id: row['0'],
			name: row['1'],
			personality: row['2'],
			motive: row['3'],
			rawParams: row['4'] || '',
			functions: functions,
			resources: resources,
			store: store,
			upgradeInfo: upgradeInfo,
			gachaData: gachaData,
			isSystem: true,
			nickname: row['11'] || 'Không',
			dungeonStatus: dungeonStatus // Sử dụng đối tượng đã được phân tích chính xác
		};
	}
	<!-- Hệ Thống Tu Luyện & Hoạt Động Nền Của NPC -->
	/**
	 * Phân tích và chuẩn hóa chuỗi cảnh giới, xử lý linh hoạt các biến thể.
	 * @param {string} realmString - Cảnh giới đầu vào.
	 * @returns {object|null} Đối tượng thông tin cảnh giới hoặc null.
	 */
	function getRealmInfo(realmString) {
		for (let i = 0; i < REALM_STRUCTURE.length; i++) {
			const majorInfo = REALM_STRUCTURE[i];
			if (realmString.startsWith(majorInfo.name)) {
				const minorPart = realmString.substring(majorInfo.name.length).replace('Kỳ', '').trim();
				const minorIndex = majorInfo.levels.findIndex(level => level.replace('Kỳ ', '') === minorPart);
				if (minorIndex > -1) {
					return { majorRealm: majorInfo.name, minorRealm: majorInfo.levels[minorIndex], majorIndex: i, minorIndex: minorIndex };
				}
			}
		}
		return null;
	}
	/**
	 * Trả về cảnh giới tiếp theo với định dạng chuẩn.
	 * @param {string} currentRealmStr - Cảnh giới hiện tại.
	 * @returns {string|null} Cảnh giới tiếp theo hoặc null.
	 */
	function getNextRealm(currentRealmStr) {
		const info = getRealmInfo(currentRealmStr);
		if (!info) return null;
		const currentMajorInfo = REALM_STRUCTURE[info.majorIndex];
		if (info.minorIndex + 1 < currentMajorInfo.levels.length) {
			return `${info.majorRealm} ${currentMajorInfo.levels[info.minorIndex + 1]}`;
		} else if (info.majorIndex + 1 < REALM_STRUCTURE.length) {
			const nextMajorInfo = REALM_STRUCTURE[info.majorIndex + 1];
			return `${nextMajorInfo.name} ${nextMajorInfo.levels[0]}`;
		}
		return null;
	}

	/**
	 * Chuyển đổi số phút thành chuỗi mô tả chi tiết.
	 * @param {number} totalMinutes - Tổng số phút đã trôi qua.
	 * @returns {string} Chuỗi mô tả thời gian.
	 */
	function formatTimePassed(totalMinutes) {
		if (totalMinutes < 60) return `${Math.round(totalMinutes)} phút`;
		if (totalMinutes < 1440) return `${Math.floor(totalMinutes / 60)} giờ`;
		const days = Math.floor(totalMinutes / 1440);
		const hours = Math.floor((totalMinutes % 1440) / 60);
		if (days < 30) return `${days} ngày ${hours} giờ`;
		const months = Math.floor(days / 30);
		const remainingDays = days % 30;
		if (days < 365) return `${months} tháng ${remainingDays} ngày`;
		const years = Math.floor(days / 365);
		const remainingMonths = Math.floor((days % 365) / 30);
		return `${years} năm ${remainingMonths} tháng`;
	}

	/**
	 * Tự động kiểm tra và tăng tuổi cho tất cả nhân vật khi năm trong game thay đổi.
	 * @returns {Promise<boolean>} Trả về true nếu có nhân vật được tăng tuổi.
	 */
	async function handleAutomaticAging() {
		const timeRow = (currentState['4'] || [])[0];
		if (!timeRow || !timeRow['0']) return false;

		// 1. Trích xuất năm hiện tại từ chuỗi thời gian
		const timeString = timeRow['0'];
		const yearMatch = timeString.match(/Năm (\d{4})/);
		if (!yearMatch) return false;

		const currentYear = parseInt(yearMatch[1]);

		// 2. Khởi tạo năm lần đầu tiên
		if (lastProcessedYear === null) {
			lastProcessedYear = currentYear;
			return false;
		}

		// 3. Kiểm tra xem năm có tăng lên không
		if (currentYear > lastProcessedYear) {
			const ageIncrease = currentYear - lastProcessedYear;
			let charactersAged = [];

			const allCharIds = Object.keys(currentState['0'] || {});

			// 4. Lặp qua tất cả nhân vật (bao gồm người chơi)
			for (const charId of allCharIds) {
				const charRow = currentState['0'][charId];
				const remarks = parseRemarksString(charRow['9'] || '');
				const currentAge = parseInt(remarks['Tuổi']);

				// 5. Kiểm tra snapshot: Nếu AI đã tự tăng tuổi rồi thì bỏ qua
				if (characterAgeSnapshot[charId] !== undefined && characterAgeSnapshot[charId] !== currentAge) {
					console.log(`Bỏ qua tăng tuổi tự động cho ${charId} vì AI đã cập nhật tuổi.`);
					continue;
				}

				if (!isNaN(currentAge)) {
					const newAge = currentAge + ageIncrease;
					remarks['Tuổi'] = newAge;
					charRow['9'] = serializeRemarksObject(remarks);
					charactersAged.push(`${(charRow['1'] || '|').split('|')[0]} (${ageIncrease} tuổi)`);
				}
			}

			// 6. Cập nhật năm đã xử lý và thông báo
			lastProcessedYear = currentYear;
			if (charactersAged.length > 0) {
				showDanmaku(`Năm tháng thoi đưa, ${charactersAged.join(', ')} đã thêm tuổi mới.`, 'world');
				return true; // Báo hiệu rằng đã có sự thay đổi
			}
		}
		return false;
	}
	/**
	 * Hàm tổng hợp xử lý toàn bộ hoạt động nền của NPC.
	 * Đọc và ghi trực tiếp vào biến số thời gian (currentState).
	 */
	function checkAndTriggerNPCBackgroundActivity() {
		const timeRow = (currentState['4'] || [])[0];
		if (!timeRow || !timeRow['0']) return;
		if (!currentState['0'] || Object.keys(currentState['0']).length <= 1) return;

		const fullTimeString = timeRow['0'].split('/')[0].trim();
		const currentDate = parseGameDate(fullTimeString);

		if (!timeRow['1'] || !timeRow['2']) {
			timeRow['1'] = fullTimeString.match(/Năm \d{4} Tháng \d{2} Ngày \d{2}/)[0];
			timeRow['2'] = fullTimeString;
			saveCurrentState();
			return;
		}

		let hasAnyStateChange = false;
		const prevCultivationDate = parseGameDate(timeRow['1']);
		const daysPassed = (currentDate - prevCultivationDate) / 86400000;

		if (daysPassed >= 1) {
			const successfulBreakthroughNpcs = [];
			const failedBreakthroughNpcs = [];

			for (const npcId in currentState['0']) {
				if (npcId === 'B1') continue;

				const npcRow = currentState['0'][npcId];
				const npcName = (npcRow['1'] || '|').split('|')[0];
				const originalRealm = (npcRow['2'] || '|').split('|')[0].trim();
				const npcMetadata = robustJSONParse(npcRow['14'] || '{}', {});

				let currentProgress = parseFloat(npcMetadata.progress) || 0;
				let tempRealm = originalRealm;
				const aptitude = npcMetadata.aptitude || "Trung Đẳng";
				const modifier = APTITUDE_MODIFIERS[aptitude] || 1.0;
				let daysRemaining = Math.floor(daysPassed);
				let hasSuccessfulBreakthrough = false;
				let lastBreakthroughFailure = false;

				while (daysRemaining > 0 && tempRealm) {
					const realmInfo = getRealmInfo(tempRealm);
					if (!realmInfo) break;

					const progressionInfo = NPC_PROGRESSION_DATA[realmInfo.majorRealm];
					if (!progressionInfo) break;

					const daysNeededFor100Percent = progressionInfo.base_days_per_level * modifier;
					if (daysNeededFor100Percent <= 0) break;

					const progressNeeded = 100 - currentProgress;
					const daysToLevelUp = (progressNeeded / 100) * daysNeededFor100Percent;

					if (daysRemaining >= daysToLevelUp) {
						daysRemaining -= daysToLevelUp;
						const nextRealmStr = getNextRealm(tempRealm);

						if (!nextRealmStr) { // Đã max cấp
							currentProgress = 100; break;
						}

						const nextRealmInfo = getRealmInfo(nextRealmStr);
						const isMajorBreakthrough = realmInfo.majorRealm !== nextRealmInfo.majorRealm;

						if (isMajorBreakthrough) {
							const successRate = BREAKTHROUGH_SUCCESS_RATES[aptitude] || 66;
							if (Math.random() * 100 <= successRate) { // Đột phá ĐẠI CẢNH GIỚI thành công
								tempRealm = nextRealmStr;
								currentProgress = 0;
								hasSuccessfulBreakthrough = true;
								lastBreakthroughFailure = false; // Thành công sẽ xóa dấu vết thất bại trước đó
							} else { // Thất bại
								currentProgress = 0; // Tiến độ về 0
								lastBreakthroughFailure = true; // Đánh dấu thất bại
								// tempRealm không đổi, NPC bị kẹt lại
							}
						} else { // Đột phá TIỂU CẢNH GIỚI (luôn thành công)
							tempRealm = nextRealmStr;
							currentProgress = 0;
							hasSuccessfulBreakthrough = true;
						}
					} else {
						currentProgress += (daysRemaining / daysNeededFor100Percent) * 100;
						daysRemaining = 0;
					}
				}

				const finalProgress = Math.min(100, currentProgress).toFixed(12);

				if (hasSuccessfulBreakthrough) {
					const identity = (npcRow['2'] || '|').split('|')[1] || 'Tán Tu';
					const realmInfo = getRealmInfo(tempRealm);
					const newRealmString = realmInfo ? `${realmInfo.majorRealm} Kỳ ${realmInfo.minorRealm}` : tempRealm;

					npcRow['2'] = `${newRealmString}|${identity}`;
					npcMetadata.progress = finalProgress;
					npcMetadata.breakthrough_failed = false; // Cập nhật trạng thái thành công
					npcRow['14'] = JSON.stringify(npcMetadata);

					hasAnyStateChange = true;
					successfulBreakthroughNpcs.push({ name: npcName, id: npcId, oldRealm: originalRealm, newRealm: newRealmString });
				} else if (lastBreakthroughFailure) {
					npcMetadata.progress = finalProgress; // Vẫn là 0
					npcMetadata.breakthrough_failed = true; // Ghi nhận thất bại
					npcRow['14'] = JSON.stringify(npcMetadata);

					hasAnyStateChange = true;
					failedBreakthroughNpcs.push({ name: npcName, id: npcId, realm: originalRealm });
				} else if (parseFloat(npcMetadata.progress || 0).toFixed(12) !== finalProgress) {
					npcMetadata.progress = finalProgress;
					npcRow['14'] = JSON.stringify(npcMetadata);
					hasAnyStateChange = true;
				}
			}

			if (successfulBreakthroughNpcs.length > 0) {
				const list = successfulBreakthroughNpcs.map(n => `- [${n.name}] (ID: ${n.id}) đã đột phá từ [${n.oldRealm}] lên [${n.newRealm}]`).join('\n');
				const command = `${getForcefulCommandPrefix()} Các NPC sau đã đột phá thành công:\n${list}\n\nYêu cầu AI nâng cấp toàn diện cho họ (cập nhật cột 9-Thọ Nguyên (nếu đột phá đại cảnh giới), cột 11-Thuộc tính [Đảm bảo tuân theo dữ liệu Bảng Đồng Bộ Thuộc Tính Cảnh Giới], sau đó là trang bị & vật phẩm) => Sử dụng các lệnh \`add\` equipment & inventory (cột 9) để nâng cấp trang bị/túi trữ vật.`;
				addAction('npc_batch_breakthrough_update', {}, {}, command, true);
			}

			if (failedBreakthroughNpcs.length > 0) {
				const list = failedBreakthroughNpcs.map(n => `- [${n.name}] (ID: ${n.id}) khi đang cố đột phá từ [${n.realm}]`).join('\n');
				const command = `${getForcefulCommandPrefix()} **CẢNH BÁO!** Các NPC sau đã đột phá đại cảnh giới THẤT BẠI:\n${list}\n\nYêu cầu AI mô tả hậu quả: Thường chỉ bị trọng thương, đạo tâm tổn thương, (hoặc tẩu hỏa nhập ma do tư chất thấp kém); Nếu từ Kết Đan trở lên, (có thể) nhận phải hậu quả nghiêm trọng do tư chất thường/thấp kém (tẩu hỏa nhập ma[cao hơn], đạo tâm sụp đổ, chết ngay tại chỗ, hoặc hậu quả lâu dài khác[cao hơn]). Sau đó cập nhật cột 4-Trạng thái, cột 12-Tâm tư cho phù hợp. Tuy nhiên vẫn phải cập nhật TOÀN BỘ cột 11 (Thuộc tính chi tiết) tương ứng với cảnh giới của họ, và thêm trang bị/vật phẩm phù hợp cảnh giới cho họ => Sử dụng các lệnh \`add\` equipment & inventory (cột 9) để phản ánh sự thay đổi.`;
				addAction('npc_batch_failure_update', {}, {}, command, true);
			}

			timeRow['1'] = fullTimeString.match(/Năm \d{4} Tháng \d{2} Ngày \d{2}/)[0];
			hasAnyStateChange = true;
		}

		// --- 2. XỬ LÝ HOẠT ĐỘNG NỀN ---
		const prevActivityTimeObj = parseGameDate(timeRow['2']);
		const minutesPassed = (currentDate - prevActivityTimeObj) / 60000;

		let activityCommandGenerated = false;
		let npcsToUpdateForActivity = [];

		// Quyết định nhóm NPC cần cập nhật dựa trên thời gian đã trôi qua
		if (minutesPassed >= 60) { // TRÊN 1 TIẾNG: Cập nhật TẤT CẢ NPC
			npcsToUpdateForActivity = Object.values(currentState['0']).filter(npcRow => npcRow['0'] !== 'B1');
		} else if (minutesPassed > 5) { // TRÊN 5 PHÚT: Chỉ cập nhật NPC Ở XA và NPC BỊ LỖI
			for (const npcId in currentState['0']) {
				if (npcId === 'B1') continue;
				const npcRow = currentState['0'][npcId];
				const metadata = robustJSONParse(npcRow['14'] || '{}', {});

				if (metadata.isNearby === undefined || metadata.isNearby === false) {
					npcsToUpdateForActivity.push(npcRow);
				}
			}
		}

		// Nếu có NPC cần cập nhật hoạt động
		if (npcsToUpdateForActivity.length > 0) {
			const timeString = formatTimePassed(minutesPassed);
			const brokenNpcs = npcsToUpdateForActivity.filter(npc => robustJSONParse(npc['14'] || '{}').isNearby === undefined);
			const healthyNpcs = npcsToUpdateForActivity.filter(npc => robustJSONParse(npc['14'] || '{}').isNearby !== undefined);

			// Tạo lệnh cho các NPC "khỏe mạnh"
			if (healthyNpcs.length > 0) {
				const healthyNpcList = healthyNpcs.map(npcRow => `[${(npcRow['1'] || '|').split('|')[0]} (ID: ${npcRow['0']})]`).join(', ');
				const activityCommand = `${getForcefulCommandPrefix()} Đã trôi qua ${timeString} kể từ lần cuối cập nhật hoạt động nền. ` +
									  `Yêu cầu AI mô phỏng hoạt động cho các NPC sau đây: ${healthyNpcList}. ` +
									  `Hãy cập nhật các cột 4 (Trạng thái hiện tại), 9 (Ghi Chú), 12 (Tâm Tư), 13 (Quan Hệ), và 16 (Hành Động|Y Phục|Vị Trí) cho họ.` +
									  ` Trong cột 9, hãy xét việc họ có mang thêm trang bị dùng \`equipItem\`, và mang thêm vật phẩm trong túi dùng \`add\` inventory`;
				addAction('npc_activity', {}, {}, activityCommand, true);
				console.log("Cập nhật NPC khỏe mạnh!");
			}

			// Tạo lệnh sửa lỗi cho các NPC bị hỏng dữ liệu
			if (brokenNpcs.length > 0) {
				const brokenNpcList = brokenNpcs.map(npcRow => `[${(npcRow['1'] || '|').split('|')[0]} (ID: ${npcRow['0']})]`).join(', ');
				const fixCommand = `${getForcefulCommandPrefix()} **CẢNH BÁO LỖI!** Các NPC sau bị thiếu dữ liệu nền ở cột 14: ${brokenNpcList}. ` +
								   `Yêu cầu AI sửa lỗi bằng cách cập nhật TOÀN BỘ cột 14 cho họ với các biến như \`isNearby\`, \`progress\`, \`aptitude\`... Sau đó, mô phỏng hoạt động nền cho họ (Cột 9, 12, 13, 16).`+
								   ` Trong cột 9, hãy xem xét việc họ có mang thêm trang bị dùng \`equipItem\`, và mang thêm vật phẩm trong túi dùng \`add\` inventory`;
				addAction('npc_data_fix', {}, {}, fixCommand, true);
				console.log("Cập nhật NPC hỏng!");
			}

			// Cập nhật mốc thời gian sau khi đã tạo lệnh
			timeRow['2'] = fullTimeString;
			hasAnyStateChange = true;
		}

		// Nếu có bất kỳ thay đổi nào (tu luyện hoặc mốc thời gian), lưu lại
		if (hasAnyStateChange) {
			saveCurrentState();
		}
	}
