	function openSystemOperations() {
		const activeSystems = Object.values(systemDatabase);
		if (activeSystems.length === 0) {
			showCustomAlert("Hiện không có Thiên Phú Hệ Thống nào được kích hoạt."); return;
		}
		const selector = document.getElementById('system-selector');
		selector.innerHTML = '';
		activeSystems.forEach(system => {
			const option = document.createElement('option');
			option.value = system.id;
			option.textContent = system.name;
			selector.appendChild(option);
		});
		renderSystemInterface(activeSystems[0].id);
		selector.onchange = (e) => renderSystemInterface(e.target.value);
		document.getElementById('system-operations-overlay').classList.add('visible');
	}

	function renderSystemInterface(systemId) {
		const system = systemDatabase[systemId];
		if (!system) return;
		const mainContentContainer = document.querySelector('#system-operations-modal .system-operations-content-wrapper');
		mainContentContainer.innerHTML = '';

		if (system.upgradeInfo && system.upgradeInfo.isUpdating) {
			const progress = system.upgradeInfo.progress || 0;
			mainContentContainer.innerHTML = `
				<div class="system-upgrade-view">
					<div class="upgrade-text">HỆ THỐNG ĐANG NÂNG CẤP</div>
					<div class="upgrade-progress-bar">
						<div class="upgrade-progress-fill" style="width: ${progress}%;"></div>
					</div>
					<div class="upgrade-percentage">${progress}%</div>
				</div>`;
		} else {
			mainContentContainer.innerHTML = `
				<div id="system-tabs" class="char-detail-tabs"></div>
				<div id="system-tab-content-container" class="char-detail-tab-content"></div>`;
			const tabsContainer = document.getElementById('system-tabs');
			const contentContainer = document.getElementById('system-tab-content-container');

			createTab('info', 'Thông Tin Chung', tabsContainer, contentContainer);
			if (system.functions && system.functions.length > 0) {
				createTab('functions', 'Công Năng Đặc Biệt', tabsContainer, contentContainer);
			}
			if (system.functions.some(f => f.name.includes('Phó Bản'))) {
				createTab('dungeon', 'Phó Bản Thí Luyện', tabsContainer, contentContainer);
			}			
			if (system.functions.some(f => f.name.includes('Cửa Hàng'))) {
				createTab('store', 'Cửa Hàng Hệ Thống', tabsContainer, contentContainer);
			}
			if (system.functions.some(f => f.name.includes('Gacha'))) {
				createTab('gacha', 'Gacha Vận Mệnh', tabsContainer, contentContainer);
			}
			tabsContainer.querySelector('.char-detail-tab')?.click();
		}
	}

	function createTab(id, name, tabsContainer, contentContainer) {
		const tab = document.createElement('div');
		tab.className = 'char-detail-tab system-tab';
		tab.dataset.tab = id;
		tab.textContent = name;
		tabsContainer.appendChild(tab);
		const pane = document.createElement('div');
		pane.id = `tab-content-${id}`;
		pane.className = 'char-detail-tab-pane system-tab-pane hidden';
		contentContainer.appendChild(pane);

		tab.onclick = () => {
			tabsContainer.querySelectorAll('.system-tab').forEach(t => t.classList.remove('active'));
			contentContainer.querySelectorAll('.system-tab-pane').forEach(p => p.classList.add('hidden'));
			tab.classList.add('active');
			pane.classList.remove('hidden');

			// Render nội dung tab CHỈ KHI được click
			const systemId = document.getElementById('system-selector').value;
			const system = systemDatabase[systemId];
			switch(id) {
				case 'info': renderSystemInfoTab(system); break;
				case 'functions': renderSystemFunctionsTab(system); break;
				case 'dungeon': renderSystemDungeonTab(system); break;
				case 'store': renderSystemStoreTab(system); break;
				case 'gacha': renderSystemGachaTab(system); break;
			}
		};
	}

