		/* Cửa Hàng Hệ Thống */
	function renderSystemStoreTab(system) {
		const pane = document.getElementById('tab-content-store');
		if (!pane) return;

		const currencyKey = Object.keys(system.resources)[0] || 'Điểm';
		const playerCurrency = system.resources[currencyKey] || 0;
		const storeItems = system.store ? (system.store.items || []) : [];

		// 1. Định nghĩa các danh mục và các loại vật phẩm tương ứng
		const categories = {
			'Công Pháp': ['Công Pháp'],
			'Trang Bị': ['Vũ Khí', 'Hộ Giáp', 'Pháp Bảo'],
			'Vật Phẩm Tiêu Hao': ['Vật Phẩm Tiêu Hao', 'Đan Dược', 'Phù Lục'], // Thêm 'Đan Dược' cho linh hoạt
			'Nguyên Liệu': ['Nguyên Liệu'],
			'Vật Phẩm Khác': ['Vật Phẩm Khác', 'Vật Phẩm Quan Trọng']
		};

		const categorizedItems = {};
		const remainingItems = [...storeItems];

		// 2. Phân loại vật phẩm vào các danh mục đã định nghĩa
		for (const categoryName in categories) {
			categorizedItems[categoryName] = [];
			const types = categories[categoryName];
			for (let i = remainingItems.length - 1; i >= 0; i--) {
				if (types.includes(remainingItems[i].type)) {
					categorizedItems[categoryName].push(remainingItems.splice(i, 1)[0]);
				}
			}
		}
		// Những vật phẩm không thuộc các loại trên sẽ tự động vào "Vật Phẩm Khác"
		categorizedItems['Vật Phẩm Khác'].push(...remainingItems);

		// 3. Xây dựng HTML
		let contentHTML = `
			<div class="store-header">
				<p>Đơn vị tiền tệ: <span style="font-weight:bold; color:#ffcc80;">${currencyKey} (Ngươi có: ${playerCurrency})</span></p>
			</div>`;

		let hasItems = false;
		for (const categoryName in categorizedItems) {
			const items = categorizedItems[categoryName];
			if (items.length > 0) {
				hasItems = true;
				contentHTML += `
					<div class="store-category">
						<h5 class="store-category-title">${categoryName}</h5>
						<div class="store-item-row">
							${items.map(item => {
								const itemDataString = JSON.stringify(item).replace(/'/g, "&apos;");
								return `							
								<div class="store-item-card-new">
                                    <div class="store-item-name store-item-link" 
                                         data-item-details='${itemDataString}' 
                                         style="cursor: pointer;">
                                        ${item.name}
                                    </div>
									<div class="store-item-desc" title="${item.desc}">${item.desc}</div>
									<div class="store-item-info">
										<span>Giá: <span class="store-item-cost">${item.cost}</span></span>
										<span>Còn lại: ${item.amount}</span>
									</div>
									<div class="store-item-footer">
										<input type="number" class="buy-quantity-input" value="1" min="1" max="${item.amount}">
										<button class="major-action-button buy-item-btn" 
												data-system-id="${system.id}" 
												data-item-id="${item.id}"
												data-item-name="${item.name.replace(/"/g, '&quot;')}" 
												data-item-type="${item.type}"
												data-item-desc="${(item.desc || '').replace(/"/g, '&quot;')}"
												data-item-effect="${(item.effect || 'Không').replace(/"/g, '&quot;')}"
												data-item-cost="${item.cost}"
												data-item-amount="${item.amount}"
												data-item-quality="${item.tier || 'Không rõ'}"
												${playerCurrency < item.cost ? 'disabled' : ''}>
											Mua
										</button>
									</div>
								</div>
							`}).join('')}
						</div>
					</div>`;
			}
		}

		if (!hasItems) {
			contentHTML += `<div style="text-align: center; padding: 20px; opacity: 0.7;">
				<p>Hôm nay không có hàng mới.</p>
				<button class="major-action-button" data-action="REFRESH_STORE" style="width: auto; padding: 10px 20px;">Làm Mới Cửa Hàng</button>
			</div>`;
		}

		pane.innerHTML = contentHTML;

		// 4. Gắn sự kiện cho các nút
		pane.querySelectorAll('.buy-item-btn').forEach(btn => {
			btn.onclick = () => handleBuyItem(btn);
		});
		const refreshBtn = pane.querySelector('[data-action="REFRESH_STORE"]');
		if(refreshBtn) {
			refreshBtn.onclick = (e) => handleSystemAction(system.id, e.target.dataset.action);
		}

		pane.querySelectorAll('.store-item-link').forEach(link => {
			link.addEventListener('click', () => {
				const itemData = JSON.parse(link.dataset.itemDetails);
				// Bây giờ gọi hàm showStoreItemDetail (không cần `window.`)
				showStoreItemDetail(itemData);
			});
		});		
	}

