	function findNextAvailableItemId() {
		const itemIds = Object.keys(currentState['1'] || {});
		if (itemIds.length === 0) {
			return 'I1';
		}
		const maxId = Math.max(0, ...itemIds.map(id => parseInt(id.substring(1)) || 0));
		return `I${maxId + 1}`;
	}
	// Xử lý lệnh mua hàng
	async function handleBuyItem(buttonElement) {
		const systemId = buttonElement.dataset.systemId;
		document.querySelectorAll(`#system-operations-modal .buy-item-btn`).forEach(btn => btn.disabled = true);

		try {
			const { itemId, itemName, itemType, itemDesc, itemEffect, itemCost, itemAmount, itemQuality } = buttonElement.dataset;
			const cost = parseInt(itemCost);
			const maxAmount = parseInt(itemAmount);

			const quantityInput = buttonElement.parentElement.querySelector('.buy-quantity-input');
			const quantityToBuy = parseInt(quantityInput.value);

			const currentSystemState = parseSystemData((currentState['10'] || {})[systemId]);
			const currencyKey = Object.keys(currentSystemState.resources)[0] || 'Điểm';
			const playerCurrency = currentSystemState.resources[currencyKey] || 0;
			const totalCost = cost * quantityToBuy;
			if (playerCurrency < totalCost) {
				await showCustomAlert(`Tài nguyên hiện tại không đủ để trả ${totalCost} ${currencyKey}!`);
				return;
			}
			if (isNaN(quantityToBuy) || quantityToBuy <= 0 || quantityToBuy > maxAmount) {
				await showCustomAlert("Số lượng mua không hợp lệ hoặc");
				return;
			}

			if (await showCustomConfirm(`Xác nhận dùng ${totalCost} ${currencyKey} để mua ${quantityToBuy} x [${itemName}]?`)) {
				// Cập nhật dữ liệu ngay trong bộ nhớ trước khi tạo lệnh
				const playerInventory = Object.values(currentState['1'] || {});
				const existingItem = playerInventory.find(invItem => invItem['1'] === itemName);

				if (existingItem) {
					const currentQty = parseInt(existingItem['5']) || 0;
					existingItem['5'] = (currentQty + quantityToBuy).toString();
				} else {
					const newItemId = findNextAvailableItemId();
					currentState['1'][newItemId] = { "0": newItemId, "1": itemName, "2": itemType, "3": itemDesc, "4": itemEffect, "5": quantityToBuy.toString(), "6": itemQuality || "Không rõ" };
				}

				currentSystemState.resources[currencyKey] -= totalCost;
				const storeItemIndex = currentSystemState.store.items.findIndex(i => i.id === itemId);
				if (storeItemIndex > -1) {
					currentSystemState.store.items[storeItemIndex].amount -= quantityToBuy;
					if (currentSystemState.store.items[storeItemIndex].amount <= 0) {
						currentSystemState.store.items.splice(storeItemIndex, 1);
					}
				}

				// **GIẢI PHÁP CỐT LÕI:**
				// Cập nhật trực tiếp vào currentState, sau đó lưu lại toàn bộ
				currentState['10'][systemId]['6'] = JSON.stringify(currentSystemState.resources);
				currentState['10'][systemId]['7'] = JSON.stringify(currentSystemState.store);

				await saveCurrentState();
				syncStateFromTables(); 

				renderInventory(inventoryItems); 
				showDanmaku(`Mua thành công ${quantityToBuy} x [${itemName}]!`, 'item');

				// Vẽ lại giao diện bằng dữ liệu mới nhất đã được đồng bộ
				renderSystemStoreTab(systemDatabase[systemId]);
			}
		} finally {
			document.querySelectorAll(`#system-operations-modal .buy-item-btn`).forEach(btn => btn.disabled = false);
		}
	}


	// Cập nhật vật phẩm tự động
	function checkAndTriggerStoreRefresh() {
		const timeRow = (currentState['4'] || [])[0];
		if (!timeRow || !timeRow['0']) return;
		const currentDate = (timeRow['0'].match(/Năm \d{4} Tháng \d{2} Ngày \d{2}/) || [])[0];
		if (!currentDate) return;

		// KỊCH BẢN 1: KIỂM TRA LỖI LOGIC TRƯỚC TIÊN
		const systemsWithDataButNoFunc = Object.values(systemDatabase).filter(sys => 
			(sys.store && sys.store.items && sys.store.items.length > 0) && // Có dữ liệu trong cột 7
			!sys.functions.some(fn => fn.name.includes('Cửa Hàng')) // Nhưng không có công năng trong cột 5
		);

		if (systemsWithDataButNoFunc.length > 0) {
			if (actionQueue.some(a => a.text.includes("dữ liệu Cửa Hàng không nhất quán"))) return;

			const systemNames = systemsWithDataButNoFunc.map(s => `[${s.name}]`).join(', ');
			const fixCommand = `${getForcefulCommandPrefix()} **LỖI LOGIC HỆ THỐNG!** Phát hiện các hệ thống sau có dữ liệu Cửa Hàng (cột 7) nhưng không có công năng tương ứng (cột 5): ${systemNames}. Yêu cầu AI lựa chọn 1 trong 2: hoặc thêm công năng chứa cụm từ 'Cửa Hàng' vào cột 5, hoặc làm trống dữ liệu trong cột 7 của các hệ thống này.`;
			addAction('system_logic_fix_store', { systemIds: systemsWithDataButNoFunc.map(s => s.id) }, {}, fixCommand, true);
			return; // Ưu tiên sửa lỗi, không chạy logic làm mới
		}

		// KỊCH BẢN 2: HOẠT ĐỘNG BÌNH THƯỜNG (LÀM MỚI CỬA HÀNG)
		const systemsWithStoreFunction = Object.values(systemDatabase).filter(sys => 
			sys.functions.some(fn => fn.name.includes('Cửa Hàng'))
		);

		// Nếu không có hệ thống nào có chức năng cửa hàng, thoát
		if (systemsWithStoreFunction.length === 0) return;

		// Tìm các hệ thống có cửa hàng lỗi thời
		const outdatedSystems = systemsWithStoreFunction.filter(sys => 
			sys.store && sys.store.date && sys.store.date !== currentDate
		);

		if (outdatedSystems.length > 0) {
			if (actionQueue.some(a => a.text.includes("làm mới vật phẩm trong cửa hàng"))) return;

			const systemNames = outdatedSystems.map(s => `[${s.name}]`).join(', ');
			const actionText = `${getForcefulCommandPrefix()} Phát hiện Cửa Hàng của các hệ thống sau đã sang ngày mới: ${systemNames}. Yêu cầu AI làm mới tất cả vật phẩm trong cột 7 của các hệ thống này ngay lập tức. (Đảm bảo mỗi cửa hàng có ít nhất 20 loại vật phẩm đa dạng, mô tả chi tiết, giá cả đa dạng. Nếu có nhiều hơn 2 cửa hàng thì mỗi cửa hàng chỉ nên chứa ít nhất 10 loại vật phẩm đa dạng). Phải có vài loại vật phẩm liên quan tới chủ đề của riêng hệ thống giúp ký chủ đạt hiệu quả cao hơn.`;
			addAction('system_store_refresh', { systemIds: outdatedSystems.map(s => s.id) }, {}, actionText, true);
		}
	}

	<!-- Xử lý gacha -->
	function parseGameDate(dateString) {
		// Sử dụng regex để lấy ra 3 nhóm số đầu tiên (Năm, Tháng, Ngày)
		const parts = dateString.match(/(\d+)/g);

		// Chỉ cần có đủ 3 số là có thể tạo ngày
		if (parts && parts.length >= 3) {
			const year = parseInt(parts[0]);
			const month = parseInt(parts[1]) - 1; // Tháng trong JavaScript bắt đầu từ 0
			const day = parseInt(parts[2]);

			// Tạo một đối tượng Date và thiết lập giờ về 0 để so sánh các ngày với nhau một cách chính xác
			const date = new Date(year, month, day);
			date.setHours(0, 0, 0, 0); 
			return date;
		}

		// Trả về một ngày không hợp lệ nếu không thể phân tích
		return new Date(0); 
	}

	function renderSystemGachaTab(system) {
		const pane = document.getElementById('tab-content-gacha');
		if (!pane) return;

		const gachaData = system.gachaData || { event_pool: null };
		const eventPool = gachaData.event_pool;
		const playerRealm = REALM_ORDER.find(r => currentPlayerData.realm.startsWith(r)) || 'Phàm Nhân';

		// --- HIỂN THỊ TÀI NGUYÊN ---
		const resources = system.resources;
		let resourceHTML = `<div class="gacha-resource-display">Tài nguyên hiện tại: <strong>Không có</strong></div>`;
		if (resources && Object.keys(resources).length > 0) {
			const resourceString = Object.entries(resources).map(([key, value]) => `<strong>${value.toLocaleString()} ${key}</strong>`).join(' | ');
			resourceHTML = `<div class="gacha-resource-display">Tài nguyên hiện tại: ${resourceString}</div>`;
		}

		// --- LOGIC MỚI: HIỂN THỊ BỂ THƯỜNG TỪ HẰNG SỐ ---
		const playerRealmIndex = REALM_ORDER.indexOf(playerRealm);
		const unlockedRealms = playerRealmIndex > -1 ? REALM_ORDER.slice(0, playerRealmIndex + 1) : [];

		let normalPoolsHTML = '';
		if (unlockedRealms.length > 0) {
