								<button class="major-action-button" data-pool-type="normal" data-realm="${realmName}" data-pull-count="10" ${playerCurrency < poolData.cost * 10 ? 'disabled' : ''}>Rút 10 lần (${poolData.cost * 10} ${costType})</button>
							</div>
