		}

		let eventPoolHTML = '';
		if (eventPool && eventPool.start_date) {
			const currentDate = parseGameDate((currentState['4'] || [])[0]['0'].split('/')[0].trim());
			const startDate = parseGameDate(eventPool.start_date);
			const endDate = parseGameDate(eventPool.end_date);
			if (currentDate >= startDate && currentDate <= endDate) {
