	async function handleGachaPull(systemId, poolType, pullCount, realmName) { // Thêm realmName vào tham số
		const system = systemDatabase[systemId];
		const playerRealmDetail = currentPlayerData.realm;
		// SỬA LẠI DÒNG DƯỚI ĐÂY
		const poolData = (poolType === 'event') ? system.gachaData.event_pool : FULL_GACHA_POOLS_DATA[realmName]; 

		if (!poolData) return await showCustomAlert("Lỗi: Không tìm thấy thông tin bể Gacha.");

		const cost = poolData.cost * pullCount;
		const currencyType = poolData.cost_type;
		const currentCurrency = system.resources[currencyType] || 0;
		if (currentCurrency < cost) return await showCustomAlert("Tài nguyên không đủ!");

		const currentSystemState = parseSystemData(currentState['10'][systemId]);
		currentSystemState.resources[currencyType] -= cost;

		const results = simulateGachaPull(poolData, pullCount, playerRealmDetail);
		const newPity = (poolData.pity || 0) + pullCount;

		// Cập nhật tài nguyên vào cột 6
		currentState['10'][systemId]['6'] = JSON.stringify(currentSystemState.resources);

		if (poolType === 'event') {
			// Cập nhật PITY vào cột 10
			currentSystemState.gachaData.event_pool.pity = newPity;
			currentState['10'][systemId]['10'] = JSON.stringify(currentSystemState.gachaData.event_pool);
		}

		await saveCurrentState();
		syncStateFromTables();
		renderSystemGachaTab(systemDatabase[systemId]);

		const commandText = `${getForcefulCommandPrefix()} Hệ thống [${system.name}] thông báo: Người chơi vừa thực hiện rút ${pullCount} lần từ bể [${poolData.name}]. ` +
							`${cost} ${currencyType} đã bị trừ. ${poolType === 'event' ? `Pity đã được cập nhật lên ${newPity} trong cột 10.` : ''} ` +
							`Yêu cầu AI dựa vào kết quả phẩm chất dưới đây để tạo ra các vật phẩm tương ứng và thêm vào túi trữ vật của người chơi: ` +
							`${JSON.stringify(results)}. (Lưu ý: AI phải trả về một HTML đẹp đẽ sinh động cho kết quả quay gacha này (chỉ dùng inline styles), nghiêm cấm dùng class style (sẽ làm hỏng giao diện), các vật phẩm hiện ra theo cấu trúc [Tên, phẩm chất, loại, mô tả, hiệu quả, số lượng], đối với những vật phẩm có phẩm chất cao hơn thì phải làm hiệu ứng và màu cho phẩm chất đó, càng cao thì càng sặc sỡ, hàng đặc biệt thì phải lộng lẫy nhất.)`;

		addAction('system_action', {}, {}, commandText, true);
		document.getElementById('system-operations-overlay').classList.remove('visible');
	}

	function simulateGachaPull(poolData, pullCount, playerRealmDetail) {
		const results = [];
		const qualitiesData = poolData.available_qualities[playerRealmDetail] || Object.values(poolData.available_qualities)[0];

		if (poolData.pity !== undefined) { // Event Pool
			let pity = poolData.pity;
			for (let i = 0; i < pullCount; i++) {
				pity++;
				let specialRate = 0;
				if (pity > 30) {
					const steps = Math.floor((pity - 30) / 10) + 1;
					specialRate = (Math.pow(2, steps) - 1) / 100;
				}

				if (Math.random() < specialRate) {
					const specialItem = poolData.special_items[Math.floor(Math.random() * poolData.special_items.length)];
					results.push({ quality: specialItem.quality, name: specialItem.name, isSpecial: true });
					pity = 0;
				} else {
					results.push(rollNormalItem(qualitiesData, false));
				}
			}
		} else { // Normal Pool
			if (pullCount === 10 && Math.random() < 0.3) {
				const bonusCount = (Math.random() < 0.8) ? 1 : 2;
				for (let i = 0; i < bonusCount; i++) results.push(rollNormalItem(qualitiesData, true));
			}
			while (results.length < pullCount) results.push(rollNormalItem(qualitiesData, false));
		}
		return results.sort((a, b) => (b.isSpecial ? 1 : 0) - (a.isSpecial ? 1 : 0)); // Đưa vật phẩm đặc biệt lên đầu
	}

	function rollNormalItem(qualitiesData, forceNext = false) {
		if (forceNext) {
			const pool = qualitiesData.next.qualities;
			const quality = pool[Math.floor(Math.random() * pool.length)];
			return { quality: quality, name: `[${quality}] Item`, isSpecial: false };
		}

		const currentPool = qualitiesData.current.qualities;
		const previousPool = qualitiesData.previous.qualities;

		// Tạo bể quay có trọng số
		let weightedPool = [];
		// 65% tỷ lệ ra phẩm chất hiện tại
		weightedPool.push(...Array(65).fill(currentPool[0]));

		// 35% tỷ lệ còn lại chia cho các phẩm chất trước đó
		if (previousPool.length === 2) {
			weightedPool.push(...Array(25).fill(previousPool[1])); // 25% cho bậc ngay trước
			weightedPool.push(...Array(10).fill(previousPool[0])); // 10% cho bậc trước nữa
		} else if (previousPool.length === 1) {
			weightedPool.push(...Array(35).fill(previousPool[0]));
		} else {
			// Nếu không có bậc trước, 100% ra bậc hiện tại
			weightedPool.push(...Array(35).fill(currentPool[0]));
		}

		const quality = weightedPool[Math.floor(Math.random() * weightedPool.length)];
		return { quality: quality, name: `[${quality}] Item`, isSpecial: false };
	}

	function checkAndTriggerGachaEventUpdate() {
		const systemWithGachaFunction = Object.values(systemDatabase).find(sys => 
			sys.functions.some(fn => fn.name.includes('Gacha'))
		);

		// TH1: Hệ thống CÓ DỮ LIỆU gacha nhưng KHÔNG CÓ CÔNG NĂNG
		// SỬA LỖI LOGIC: Chỉ kiểm tra event_pool và đảm bảo nó không phải là đối tượng rỗng.
		const systemsWithDataButNoFunc = Object.values(systemDatabase).filter(sys => 
			(sys.gachaData && (sys.gachaData.event_pool && Object.keys(sys.gachaData.event_pool).length > 0)) &&
			!sys.functions.some(fn => fn.name.includes('Gacha'))
		);

		if (systemsWithDataButNoFunc.length > 0) {
			if (actionQueue.some(a => a.text.includes("dữ liệu Gacha không nhất quán"))) return;

			const systemNames = systemsWithDataButNoFunc.map(s => `[${s.name}]`).join(', ');
			// Sửa lại lệnh ẩn để chỉ đề cập đến cột 10
			const fixCommand = `${getForcefulCommandPrefix()} **LỖI LOGIC HỆ THỐNG!** Phát hiện các hệ thống sau có dữ liệu Gacha Sự Kiện (cột 10) nhưng không có công năng Gacha tương ứng (cột 5): ${systemNames}. Yêu cầu AI lựa chọn 1 trong 2: hoặc thêm công năng chứa chữ 'Gacha' vào cột 5, hoặc làm trống dữ liệu trong cột 10 của các hệ thống này.`;
			addAction('system_logic_fix_gacha', { systemIds: systemsWithDataButNoFunc.map(s => s.id) }, {}, fixCommand, true);
			return;
		}

		// Nếu không có hệ thống nào có chức năng Gacha, không cần chạy logic bên dưới
		if (!systemWithGachaFunction) return;

		// Logic tạo sự kiện mới (chỉ chạy khi có hệ thống với công năng Gacha)
		const system = systemWithGachaFunction;
		const currentDate = parseGameDate((currentState['4'] || [])[0]['0'].split('/')[0].trim());
		if (actionQueue.some(a => a.text.includes("tạo một sự kiện Gacha mới"))) return;

		const eventPool = system.gachaData.event_pool;
		let commandText = null;

		if (!eventPool || Object.keys(eventPool).length === 0) { // Kiểm tra cả trường hợp là đối tượng rỗng
			const activationDate = parseGameDate("Năm 0001 Tháng 01 Ngày 06");
			if (currentDate >= activationDate) {
				commandText = `${getForcefulCommandPrefix()} Hệ thống [${system.name}] phát hiện chưa có sự kiện Gacha. Yêu cầu AI tạo một sự kiện Gacha mới sáng tạo (hoặc dành cho dịp lễ nào đó) và cập nhật vào cột 10 của hệ thống, bắt đầu sau 5-10 ngày và kéo dài 7-14 ngày. Sau khi tạo, hãy thông báo cho ký chủ về sự kiện này`;
			}
		} else if (eventPool.end_date) {
			const daysSinceEnd = (currentDate - parseGameDate(eventPool.end_date)) / 86400000;
			if (daysSinceEnd > 6) {
				const playerRealm = REALM_ORDER.find(r => currentPlayerData.realm.startsWith(r)) || 'Phàm Nhân';
				const qualityDataForEvent = FULL_GACHA_POOLS_DATA[playerRealm]?.available_qualities || {};

				commandText = `${getForcefulCommandPrefix()} Hệ thống [${system.name}] báo cáo: Sự kiện Gacha [${eventPool.name}] đã kết thúc hơn 6 ngày. Yêu cầu AI xóa dữ liệu bể sự kiện cũ và tạo một sự kiện Gacha mới, sáng tạo (hoặc dành cho dịp lễ nào đó) để cập nhật vào cột 10. `+
							  `**Quan trọng:** Hãy sao chép chính xác cấu trúc "available_qualities" sau đây vào sự kiện mới: \`${JSON.stringify(qualityDataForEvent)}\`. ` +
							  `Sự kiện nên bắt đầu sau 5-10 ngày và kéo dài 7-14 ngày. Sau khi tạo, hãy thông báo cho ký chủ về sự kiện này.`;
			}
		}

		if (commandText) {
			addAction('system_action', {}, {}, commandText, true);
		}
	}

