	// THÊM MỚI: Hàm kiểm tra và nhắc nhở AI cập nhật phó bản đặc biệt
	function checkAndTriggerSpecialDungeonUpdate() {
		const systemWithDungeonFunc = Object.values(systemDatabase).find(sys =>
			sys.functions.some(fn => fn.name.includes('Phó Bản'))
		);
		if (!systemWithDungeonFunc) return;

		const timeRow = (currentState['4'] || [])[0];
		if (!timeRow || !timeRow['0']) return;
		const currentDate = parseGameDate(timeRow['0'].split('/')[0].trim());

		const specialDungeons = JSON.parse(systemWithDungeonFunc.dungeonStatus.specialDungeonData || '[]');

		let commandText = null;

		if (specialDungeons.length === 0) {
			// Nếu chưa có phó bản đặc biệt nào, tạo lệnh yêu cầu tạo mới
			commandText = `${getForcefulCommandPrefix()} Hệ thống [${systemWithDungeonFunc.name}] báo cáo: Hiện chưa có Phó Bản Đặc Biệt nào được mở. Yêu cầu AI ngay lập tức tạo một phó bản đặc biệt đầu tiên, dựa theo cấu trúc đã hướng dẫn. Phó bản nên bắt đầu sau 3-5 ngày và kéo dài 7-15 ngày. Sau đó hãy thông báo cho người chơi.`;
		} else {
			const lastDungeon = specialDungeons[specialDungeons.length - 1];
			const endDate = parseGameDate(lastDungeon.end_date);
			const daysSinceEnd = (currentDate - endDate) / 86400000;

			if (daysSinceEnd > 7) {
				// Nếu phó bản cuối cùng đã kết thúc hơn 7 ngày, yêu cầu tạo mới
				commandText = `${getForcefulCommandPrefix()} Hệ thống [${systemWithDungeonFunc.name}] báo cáo: Phó Bản Đặc Biệt [${lastDungeon.name}] đã kết thúc hơn 7 ngày. Yêu cầu AI xóa phó bản cũ và tạo một phó bản đặc biệt mới. Phó bản mới nên có chủ đề sáng tạo (có thể dựa vào sự kiện đặc biệt/dịp lễ sắp tới) và phù hợp với cảnh giới hiện tại của người chơi [${currentPlayerData.realm}]. Sau đó hãy thông báo cho người chơi.`;
			}
		}

		if (commandText) {
			// Tránh gửi lệnh trùng lặp
			if (actionQueue.some(a => a.text.includes("tạo một phó bản đặc biệt"))) return;
			addAction('system_dungeon_update', {}, {}, commandText, true);
		}
	}
	/**
	 * Tự động kiểm tra xem người chơi có thiên phú "Hệ Thống" nhưng lại thiếu
	 * thực thể Hệ Thống trong biến số hay không. Nếu có, tạo một lệnh ẩn yêu cầu AI tạo ra nó.
	 */
	function checkAndTriggerSystemCreation() {
		// Nếu chưa có dữ liệu người chơi hoặc thiên phú, bỏ qua
		if (!currentPlayerData || !currentPlayerData.playerTraits || currentPlayerData.playerTraits.length === 0) {
			return;
		}

		// 1. Tìm tất cả các thiên phú có chữ "Hệ Thống"
		const systemTraits = currentPlayerData.playerTraits.filter(
			trait => trait.name.includes('Hệ Thống')
		);

		// Nếu không có thiên phú nào như vậy, không cần làm gì
		if (systemTraits.length === 0) {
			return;
		}

		// 2. Lấy danh sách tên các hệ thống hiện có
		const existingSystemNames = Object.values(systemDatabase).map(sys => sys.name);

		// 3. Đối với mỗi thiên phú Hệ Thống, kiểm tra xem đã có hệ thống tương ứng chưa
		systemTraits.forEach(trait => {
			// Một cách kiểm tra đơn giản là xem có hệ thống nào chứa tên của thiên phú không
			const systemExists = existingSystemNames.some(sysName => sysName.includes(trait.name));

			if (!systemExists) {
				// 4. Nếu chưa tồn tại, kiểm tra xem đã có lệnh tạo trong hàng đợi chưa để tránh lặp lại
				const isCreationPending = actionQueue.some(
					action => action.text.includes(`tạo Hệ Thống dựa trên thiên phú [${trait.name}]`)
				);

				if (!isCreationPending) {
					// 5. Tạo lệnh ẩn yêu cầu AI tạo Hệ Thống
					console.log(`Phát hiện thiếu Hệ Thống cho thiên phú: ${trait.name}. Đang tạo lệnh...`);

					const commandText = `${getForcefulCommandPrefix()} Phát hiện người chơi có thiên phú [${trait.name}] nhưng chưa có thực thể Hệ Thống tương ứng. ` +
										`Yêu cầu AI sử dụng lệnh set để tạo một Hệ Thống mới (ID bắt đầu bằng X). ` +
										`Hãy dựa vào tên và mô tả của thiên phú "${trait.desc}" để điền đầy đủ các thông tin: Tên, Giọng Điệu, Mục Tiêu, và các cột khác cho hợp lý. ` +
										`(Hành động này diễn ra âm thầm, chỉ cập nhật biến số)`;

					addAction('system_creation', { traitName: trait.name }, {}, commandText, true); // isHidden = true
				}
			}
		});
	}
/**
 * Tự động kiểm tra các hệ thống đang trong trạng thái 'isUpdating'.
 * Nếu tiến độ đã đạt 100%, hàm sẽ tự động đặt isUpdating=false và progress=0,
 * sau đó lưu lại trạng thái và thông báo cho người chơi.
 */
async function checkAndTriggerSystemUpdateCompletion() {
    let changed = false; // Cờ để theo dõi xem có thay đổi nào không

    // Lặp qua tất cả các hệ thống đang hoạt động
    for (const systemId in systemDatabase) {
        const system = systemDatabase[systemId];

        // Kiểm tra điều kiện: Đang nâng cấp VÀ tiến độ đã đạt 100%
        if (system.upgradeInfo && system.upgradeInfo.isUpdating === true && system.upgradeInfo.progress >= 100) {

            // Lấy dòng dữ liệu gốc của hệ thống từ currentState
            const systemRow = currentState['10'][systemId];
            if (systemRow) {
                // Phân tích chuỗi JSON thông tin nâng cấp
                const upgradeInfoObj = JSON.parse(systemRow['8'] || '{}');

                // Cập nhật trạng thái
                upgradeInfoObj.isUpdating = false;
                upgradeInfoObj.progress = 0;

                // Chuyển đổi lại thành chuỗi JSON và ghi đè vào biến số
                systemRow['8'] = JSON.stringify(upgradeInfoObj);

                changed = true; // Đánh dấu là đã có thay đổi

                // Gửi thông báo cho người dùng
                showDanmaku(`Hệ thống [${system.name}] đã hoàn tất nâng cấp!`, 'world');
            }
        }
    }

    // Nếu có bất kỳ thay đổi nào, hãy lưu và đồng bộ lại trạng thái
    if (changed) {
        await saveCurrentState();
        syncStateFromTables(); // Rất quan trọng để cập nhật lại systemDatabase cho lượt tiếp theo
    }
}

async function handleSystemAction(systemId, actionKey, context = {}) {
    const button = document.querySelector(`.function-detail button[data-action="${actionKey}"]`);
    if (button) button.disabled = true;

    try {
        const currentSystemState = parseSystemData((currentState['10'] || {})[systemId]);
        if (!currentSystemState) return;

        let actionText = `『Lệnh thao tác từ {{user}} gửi đến, Hệ Thống Chủ Decal yêu cầu [${currentSystemState.name}] `;
		showCustomAlert("Đã yêu cầu cập nhật. Hãy tiếp tục tin nhắn.");
        const func = currentSystemState.functions.find(f => f.action_key === actionKey);

        // Xử lý các hành động không có chi phí hoặc UI
        if (!func || !func.cost) {
            switch (actionKey) {
                case 'REFRESH_STORE': actionText += ` làm mới Cửa Hàng.]`; break;
                case 'PULL_GACHA_1': actionText += ` thực hiện quay Gacha 1 lần tại [${context.poolName}].』`; break;
                case 'PULL_GACHA_10': actionText += ` thực hiện quay Gacha 10 lần tại [${context.poolName}].』`; break;
                default: actionText += func ? ` sử dụng chức năng [${func.name}].』` : `, thực hiện một hành động không rõ.』`;
            }
            addAction('system_action', { systemId, actionKey, context }, {}, actionText, true);
            document.getElementById('system-operations-overlay').classList.remove('visible');
            return;
        }

        const costParts = func.cost.toString().split(' ');
        const costValue = parseInt(costParts[0]) || 0;
        const currencyKey = costParts.length > 1 ? costParts.slice(1).join(' ') : (Object.keys(currentSystemState.resources)[0] || 'Điểm');
        const playerCurrency = currentSystemState.resources[currencyKey] || 0;

        if (playerCurrency < costValue) {
            await showCustomAlert(`Tài nguyên không đủ! Cần ${costValue} ${currencyKey}.`);
            return;
        }

        if (await showCustomConfirm(`Xác nhận dùng ${func.cost} ${currencyKey} để sử dụng chức năng [${func.name}]?`)) {
            // **GIẢI PHÁP CỐT LÕI:**
            // Cập nhật trực tiếp vào currentState
            currentSystemState.resources[currencyKey] -= costValue;
            currentState['10'][systemId]['6'] = JSON.stringify(currentSystemState.resources);

            await saveCurrentState();
            syncStateFromTables();

            // Vẽ lại giao diện ngay lập tức với dữ liệu mới
            renderSystemFunctionsTab(systemDatabase[systemId]);

            actionText += ` sử dụng chức năng [${func.name}].』`;
            addAction('system_action', { systemId, actionKey, context }, {}, actionText, true);

            await showCustomAlert(`Đã sử dụng chức năng [${func.name}]. Lệnh đã được thêm vào hàng đợi.`);
            // Không đóng cửa sổ nữa để người dùng thấy kết quả
        }
    } finally {
        if (button) button.disabled = false;
    }
}


	<!-- Xử lý copy chỉ 1-click-->
	function makeNameCopyable(elementId, textToCopy) {
		const nameEl = document.getElementById(elementId);
		if (!nameEl) return;

		nameEl.style.cursor = 'pointer';
		nameEl.title = 'Nhấp để sao chép';

		nameEl.onclick = async (e) => {
			e.stopPropagation();
			try {
				await navigator.clipboard.writeText(textToCopy);

				// Hiển thị thông báo "Đã copy!"
				const feedback = document.createElement('span');
				feedback.textContent = ' Đã copy!';
				feedback.style.color = '#66bb6a';
				feedback.style.fontSize = '0.8em';
				feedback.style.fontStyle = 'italic';
				nameEl.appendChild(feedback);

				setTimeout(() => {
					feedback.remove();
				}, 1500);

			} catch (err) {
				console.error('Sao chép thất bại:', err);
			}
		};
	}

