	function filterSelfSelectTraits() {
		const searchTerm = document.getElementById('trait-search-input').value.toLowerCase();

		// Lấy trạng thái của nút lọc 'Hệ Thống'
		const isSystemFilterActive = document.querySelector('#trait-filter-system-btn')?.classList.contains('active');

		// Lấy danh sách tất cả các độ hiếm đang được chọn
		const selectedRarityNodes = document.querySelectorAll('#trait-filter-container .inv-cat-btn.active[data-rarity]');
		const selectedRarities = Array.from(selectedRarityNodes).map(btn => btn.dataset.rarity);

		// Kiểm tra xem nút 'Tất cả' có đang được chọn không
		const isAllSelected = selectedRarities.includes('all');

		document.querySelectorAll('#self-select-trait-grid .trait-card').forEach(card => {
			const traitName = card.dataset.traitName.toLowerCase();
			const traitRarity = card.dataset.rarity;

			// Điều kiện 1: Khớp độ hiếm
			// Hoặc là nút 'Tất cả' được chọn, hoặc độ hiếm của thẻ nằm trong danh sách đã chọn
			const rarityMatch = isAllSelected || selectedRarities.includes(traitRarity);

			// Điều kiện 2: Khớp từ khóa tìm kiếm
			const searchMatch = traitName.includes(searchTerm);

			// Điều kiện 3: Khớp bộ lọc 'Hệ Thống'
			// Hoặc là bộ lọc 'Hệ Thống' không được bật, hoặc tên thiên phú phải chứa "hệ thống"
			const systemMatch = !isSystemFilterActive || traitName.includes('hệ thống');

			// Chỉ hiển thị thẻ nếu cả 3 điều kiện đều đúng
			card.style.display = (rarityMatch && searchMatch && systemMatch) ? 'flex' : 'none';
		});
	}

