            document.getElementById('ctx-delete-btn').addEventListener('click', async () => {
                if (!activeLogEntry) return;

                const logIdToDelete = activeLogEntry.dataset.logId;
                const entryToRemove = activeLogEntry;
                activeLogEntry = null;

                if (!logIdToDelete) {
                    await showCustomAlert('Không thể xóa tin nhắn này: thiếu định danh duy nhất.');
                    hideContextMenu();
                    return;
                }

                if (await showCustomConfirm('Ngươi có chắc chắn muốn xóa vĩnh viễn tin nhắn này không? Thao tác này sẽ xóa nó khỏi lịch sử trò chuyện.')) {
                    entryToRemove.remove();
                    try {
                        const archive = await db.archives.get(currentArchiveName);
                        const logIndex = archive.data.logs.findIndex(log => log.id === logIdToDelete);

                        if (logIndex > -1) {
                            archive.data.logs.splice(logIndex, 1);
                            await db.archives.put(archive);
                        }
                    } catch(e) { console.error('Xóa tin nhắn ở backend thất bại:', e); await showCustomAlert('Xóa ở backend thất bại.'); }
                }
