        async function handleResummarize(logId) {
            if (!await showCustomConfirm("Ngươi có chắc chắn muốn tổng kết lại bản ghi này không? Tổng kết cũ sẽ bị ghi đè.")) return;

            let archive = await db.archives.get(currentArchiveName);
            let logs = archive.data.logs;
            const summaryLogIndex = logs.findIndex(log => log.id === logId);
            if (summaryLogIndex === -1) {
                await showCustomAlert("Lỗi: Không tìm thấy bản ghi cần tổng kết lại.");
                return;
            }

            const summaryLog = logs[summaryLogIndex];
            const rangeMatch = summaryLog.content.match(/\[Thiên Đạo Tổng Kết: (\d+)-(\d+) tầng\]/);
            if (!rangeMatch) {
                await showCustomAlert("Lỗi: Không thể phân tích phạm vi tầng hợp lệ từ tổng kết này.");
                return;
            }

            const start = parseInt(rangeMatch[1]);
            const end = parseInt(rangeMatch[2]);

            const chatLogs = logs.filter(log => !log.content.startsWith('[Thiên Đạo Tổng Kết:') && !log.content.includes('<h4>Thiên Đạo Khai Mở</h4>'));
            const logsToSummarize = chatLogs.slice(start - 1, end);

            if (logsToSummarize.length === 0) {
                await showCustomAlert("Lỗi: Không tìm thấy bản ghi gốc để tổng kết lại.");
                return;
            }

            const textToSummarize = logsToSummarize.map(log => log.content).join('\n---\n');
            const summaryResult = await callSummaryApi(textToSummarize);

            if (summaryResult) {
                summaryLog.content = `[Thiên Đạo Tổng Kết: ${start}-${end} tầng]\n${summaryResult}`;
                archive.data.logs = logs;
                await db.archives.put(archive);

                await showCustomAlert("Tổng kết lại thành công!");
                showSummaryDetail(logId);
                loadChatHistory(logs);
            }
        }

        async function openMessageEditor(logId) {
            currentEditingMessageId = logId;
            const archive = await db.archives.get(currentArchiveName);
            const logToEdit = archive.data.logs.find(log => log.id === logId);

