		<!-- THÊM MỚI MOD (ALL): Xử lý nút tải lại lượt trước -->
		async function handleReloadPreviousTurn() {
			if (!await showCustomConfirm('Bạn có chắc muốn tải lại lượt trước không?\nThao tác này sẽ xóa lượt đi cuối cùng (cả của bạn và AI nếu có), khôi phục trạng thái của lượt trước đó và điền lại nội dung nhập liệu của bạn.')) {
				return;
			}

			try {
				const archive = await db.archives.get(currentArchiveName);
				if (!archive) throw new Error("Không tìm thấy lưu trữ hiện tại.");

				const logs = archive.data.logs;
				let targetLogIdToRestore;
				let textToRepopulate;

				// 1. Tìm chỉ mục của log AI và log người dùng cuối cùng
				const lastAiLogIndex = logs.findLastIndex(log => log.type === 'ai' && log.stateSnapshot);
				const lastUserLogIndex = logs.findLastIndex(log => log.type === 'user');

				// 2. Xác định kịch bản: Lượt đi thành công hay thất bại?
				if (lastUserLogIndex > lastAiLogIndex) {
					// TH1: Lượt đi thất bại (log cuối cùng là của người dùng)
					console.log("Phát hiện lượt đi thất bại, đang tải lại...");

					const lastAiLog = logs[lastAiLogIndex];
					if (!lastAiLog || !lastAiLog.stateSnapshot) {
						throw new Error("Không tìm thấy snapshot hợp lệ ở lượt AI thành công cuối cùng để quay lại.");
					}
					// Mục tiêu khôi phục là trạng thái của log AI cuối cùng
					targetLogIdToRestore = lastAiLog.id;

					// Nội dung cần điền lại là từ log người dùng "mồ côi"
					textToRepopulate = logs[lastUserLogIndex].content.replace(/^> /, '');

				} else {
					// TH2: Lượt đi thành công (log cuối cùng là của AI)
					console.log("Phát hiện lượt đi thành công, đang tải lại...");

					const aiLogsWithSnapshots = logs.filter(log => log.type === 'ai' && log.stateSnapshot);
					if (aiLogsWithSnapshots.length < 2) {
						throw new Error("Không có lượt đi trước đó để tải lại (đây có thể là lượt đầu tiên). Hãy vào Khoảnh Khắc Nhân Sinh để quay trở lại!");
					}
					// Mục tiêu khôi phục là trạng thái của log AI ÁP CHÓT
					targetLogIdToRestore = aiLogsWithSnapshots[aiLogsWithSnapshots.length - 2].id;

					// Nội dung cần điền lại vẫn là từ log người dùng cuối cùng
					textToRepopulate = logs[lastUserLogIndex].content.replace(/^> /, '');
				}

				// 3. Thực hiện quay ngược thời gian và điền lại ô chat
				await loadStateFromLog(targetLogIdToRestore);
				messageInput.value = textToRepopulate;
				messageInput.focus();

				await showCustomAlert('Đã tải lại lượt trước thành công!');

			} catch (error) {
				console.error("Tải lại lượt trước thất bại:", error);
				await showCustomAlert(`Tải lại thất bại: ${error.message}`);
			}
		}

		<!-- THÊM MỚI MOD: Xóa hàng đợi nếu quay ngược & load lại lorebook -->
        async function loadStateFromLog(logId) {
			<!-- Bắt đàu -->
			actionQueue = [];
			renderActionQueue();
			<!-- Kết thúc -->
            let archive = await db.archives.get(currentArchiveName);
            let logs = archive.data.logs;
            const logIndex = logs.findIndex(l => l.id === logId);

            if (logIndex === -1 || !logs[logIndex].stateSnapshot) {
                await showCustomAlert('Khôi phục thất bại: Không tìm thấy Khoảnh Khắc Nhân Sinh tương ứng.');
                return;
            }

            try {
                const snapshotState = JSON.parse(logs[logIndex].stateSnapshot);
                currentState = snapshotState;
                syncStateFromTables();
            } catch(e) {
                await showCustomAlert('Khôi phục thất bại: Định dạng dữ liệu Khoảnh Khắc Nhân Sinh không chính xác.');
                console.error("Lỗi khi phân tích Khoảnh Khắc Nhân Sinh:", e);
                return;
            }

            logs.splice(logIndex + 1);
            archive.data.logs = logs;
            await db.archives.put(archive);

            await saveCurrentState();

            loadChatHistory(logs);
            renderPlayerAttributes(currentPlayerData);
            renderInventory(inventoryItems);
            updateAvatar(currentPlayerData);

			await manageLorebookEntries(); <!-- Dòng mới -->
            await showCustomAlert('Khoảnh Khắc Nhân Sinh đã được tải thành công!');
            snapshotOverlay.classList.remove('visible');
        }

        async function openSnapshotEditor(logId) {
            currentEditingSnapshotLogId = logId;
            const archive = await db.archives.get(currentArchiveName);
            const log = archive.data.logs.find(l => l.id === logId);
            if (log && log.stateSnapshot) {
                try {
                    const snapshotObject = JSON.parse(log.stateSnapshot);
                    document.getElementById('snapshot-editor-textarea').value = JSON.stringify(snapshotObject, null, 2);
                } catch (e) {
                    document.getElementById('snapshot-editor-textarea').value = log.stateSnapshot;
                }
                snapshotEditorOverlay.classList.add('visible');
            }
        }

        async function saveSnapshotEdit() {
            if (!currentEditingSnapshotLogId) return;

            const textarea = document.getElementById('snapshot-editor-textarea');
            const newSnapshot = textarea.value;

            try {
                const parsedSnapshot = JSON.parse(newSnapshot);
                if (typeof parsedSnapshot !== 'object' || parsedSnapshot === null || Array.isArray(parsedSnapshot)) {
                    throw new Error("Khoảnh khắc phải là một đối tượng chứa các khóa bảng.");
                }
            } catch (e) {
                await showCustomAlert(`Định dạng không chính xác, không thể lưu: ${e.message}`);
                return;
            }

            if (await showCustomConfirm('Định dạng chính xác. Ngươi có chắc chắn muốn lưu các thay đổi đối với Khoảnh Khắc Nhân Sinh này không?')) {
                let archive = await db.archives.get(currentArchiveName);
                let logs = archive.data.logs;
                const logIndex = logs.findIndex(l => l.id === currentEditingSnapshotLogId);
                if (logIndex !== -1) {
                    logs[logIndex].stateSnapshot = newSnapshot;
                    archive.data.logs = logs;
                    await db.archives.put(archive);
                    await showCustomAlert('Khoảnh khắc đã được sửa đổi thành công!');
                    snapshotEditorOverlay.classList.remove('visible');
                    openSnapshotManager();
                }
                currentEditingSnapshotLogId = null;
            }
        }

