<!-- THÊM MỚI MOD: TÌm kiếm linh căn -->
        function createLinggenOrb(name, isSelectable = false) {
            if (!name) return document.createElement('div');

            // 1. Phân tích tên linh căn để lấy loại và các nguyên tố
            const parts = name.split(' ');
            const type = parts[0]; // ví dụ: "Chân Linh Căn"
            const elements = parts.slice(1).map(el => el.replace(',', '')); // ví dụ: ["Mộc", "Lôi"]

            // Nếu không thể phân tích ra loại, trả về một div trống
            if (!type) return document.createElement('div');

            // 2. Thử lấy dữ liệu được thiết lập sẵn từ cấu hình (chủ yếu để lấy chi phí khi tự chọn)
            const data = CREATION_CONFIG.LINGGEN[name];

            const orb = document.createElement('div');
            // 3. Kiểu dáng chỉ phụ thuộc vào `type` đã phân tích
            orb.className = `linggen-orb orb-type-${type}`;
			orb.dataset.linggenName = name; <!-- Dòng mới -->
            orb.innerHTML = `
				<button class="trait-detail-btn" style="position: absolute; top: 5px; right: 5px; background: none; border: none; color: rgba(255,255,255,0.7); cursor: pointer; font-size: 1em;"><i class="fas fa-info-circle"></i></button> <!-- THêm dòng mới -->
                <div class="linggen-tag tag-type-${type}">${type}</div>
                <div class="linggen-elements">${elements.join(' ')}</div>
                ${(isSelectable && data) ? `<div class="linggen-cost">${data.cost} điểm</div>` : ''}
            `;

			<!-- THÊM SỰ KIỆN -->
			const detailBtn = orb.querySelector('.trait-detail-btn');
			detailBtn.addEventListener('click', (e) => {
				e.stopPropagation(); // Ngăn không cho sự kiện click lan ra ngoài để chọn linh căn
				const linggenData = { name: name, ...CREATION_CONFIG.LINGGEN[name] };
				showLinggenDetail(linggenData);
			}); <!-- END -->

            // 4. Nếu dùng cho bảng tự chọn, thêm sự kiện nhấp chuột
            if (isSelectable && data) {
                orb.onclick = async () => {
                    const oldCost = creationState.selectedLinggen ? (CREATION_CONFIG.LINGGEN[creationState.selectedLinggen]?.cost || 0) : 0;
                    if (calculateRemainingPoints() + oldCost < data.cost) {
                        await showCustomAlert('Điểm không đủ, không thể chọn linh căn này!');
                        return;
                    }
					creationState.linggenIsRandom = false;
                    creationState.selectedLinggen = name;
                    selfSelectLinggenOverlay.classList.remove('visible');
                    renderCreationStep();
                };
            }

            return orb;
        }

<!-- THÊM MỚI MƠD: XỬ lý linh căn ngẫu nhiên -->
		async function handleRandomizeLinggen() {
			const cost = 3; // THAY ĐỔI 1: Chi phí cố định cho mỗi lần quay là 3 điểm.

			// Bước 1: Hoàn lại điểm của linh căn đã chọn trước đó (nếu có)
			const oldCost = 0;

			// Bước 2: Kiểm tra xem có đủ điểm để quay không
			// (Điểm còn lại + điểm hoàn lại) phải lớn hơn hoặc bằng chi phí quay
			if (calculateRemainingPoints() + oldCost < cost) {
				await showCustomAlert('Điểm thuộc tính không đủ (cần 3 điểm), không thể xác định linh căn!');
				return;
			}

			// Bước 3: Trừ chi phí quay cố định
			// Chúng ta sẽ tính lại tổng điểm: điểm hiện có, cộng lại điểm cũ, rồi trừ đi 2.
			creationState.totalPoints -= cost;
			creationState.selectedLinggen = null; // Tạm thời xóa linh căn cũ

			// Bước 4: Chuẩn bị các bậc Linh Căn
			const allLinggen = CREATION_CONFIG.LINGGEN;
			const tiers = {
				thanTich: [],       // Thần Tích
				truyenThuyet: [],   // Truyền Thuyết
				suThi: [],          // Sử Thi
				hiemCo: [],         // Hiếm Có
				phoThong: [],       // Phổ Thông
				tieuCuc: [],         // Tiêu Cực
				sieuTieuCuc: [] 	// Siêu Tiêu Cực
			};

			for (const name in allLinggen) {
				const linggenData = allLinggen[name];
				if (linggenData.cost >= 99999) tiers.thanTich.push(name);
				else if (linggenData.cost >= 6000) tiers.truyenThuyet.push(name);
				else if (linggenData.cost > 1000) tiers.suThi.push(name);
				else if (linggenData.cost > 100) tiers.hiemCo.push(name);
				else if (linggenData.cost >= 0) tiers.phoThong.push(name);
				else if (linggenData.cost < -1000) tiers.sieuTieuCuc.push(name); // Ngưỡng cho Siêu Tiêu Cực
				else if (linggenData.cost < 0) tiers.tieuCuc.push(name);
			}

			// Bước 5: Quay số ngẫu nhiên với tỷ lệ được điều chỉnh
			const roll = Math.random() * 100;
			let selectedTier;

			if (creationState.isExtreme) {
				// Tỷ lệ Cực Hạn
				if (roll < 0.3) selectedTier = tiers.thanTich;
				else if (roll < 3) selectedTier = tiers.truyenThuyet;       // 3%
				else if (roll < 6) selectedTier = tiers.sieuTieuCuc;    // 3% (tương đương Truyền Thuyết)
				else if (roll < 21) selectedTier = tiers.suThi;        // 15%
				else if (roll < 41) selectedTier = tiers.hiemCo;       // 20%
				else if (roll < 71) selectedTier = tiers.phoThong;     // 30%
				else selectedTier = tiers.tieuCuc;                     // 29%
			} else {
				// Tỷ lệ thường
				if (roll < 0.3) selectedTier = tiers.thanTich;			// 0.3%
				else if (roll < 1) selectedTier = tiers.truyenThuyet;   // 1%
				else if (roll < 2) selectedTier = tiers.sieuTieuCuc;    // 1% (tương đương Truyền Thuyết)
				else if (roll < 7) selectedTier = tiers.suThi;         // 5%
				else if (roll < 27) selectedTier = tiers.hiemCo;       // 20%
				else if (roll < 67) selectedTier = tiers.phoThong;     // 40%
				else selectedTier = tiers.tieuCuc;                     // 33%
			}

			// Phòng trường hợp bậc được chọn không có linh căn nào
			if (!selectedTier || selectedTier.length === 0) {
				selectedTier = tiers.phoThong.length > 0 ? tiers.phoThong : tiers.tieuCuc;
			}

			// Bước 6: Chọn một linh căn từ bậc đã quay trúng
			const randomIndex = Math.floor(Math.random() * selectedTier.length);
			const newLinggenName = selectedTier[randomIndex];

			// Gán linh căn mới cho người chơi
			creationState.selectedLinggen = newLinggenName;
			// QUAN TRỌNG: Không trừ đi cost của linh căn mới nữa! Chi phí đã được tính ở Bước 3.

			// THAY ĐỔI 3: Xử lý trường hợp đặc biệt khi quay trúng Thần Tích
			if (selectedTier === tiers.sieuTieuCuc) {
				await showCustomAlert("CHÚC MỪNG VÔ CÙNG! Chính hệ thống ta đây cũng bất ngờ với vận đen của ngươi!");
			}
			if (selectedTier === tiers.truyenThuyet) {
				await showCustomAlert("Chúc mừng bạn trúng được Linh Căn Truyền Thuyết! Bạn rất may mắn!");
			}
			if (selectedTier === tiers.thanTich) {
				creationState.totalPoints = -999999999;
				await showCustomAlert("XIN CHÚC MỪNG! Số bạn hôm nay nhất định là đỏ toàn thân!");
			}
			// Nếu không phải Thần Tích, không cần làm gì thêm về điểm số.

			creationState.linggenIsRandom = true; <!-- Kiểm tra xem có phải đang random hay không -->
			// Bước 7: Cập nhật lại giao diện
			renderCreationStep();
		}
