        function sanitizeCustomTraitForGameState(trait) {
            /* return {
                name: trait.name,
                desc: trait.desc,
                effects: trait.effects,
                bonus: trait.bonus,
                rarity: trait.rarity
            }; Lệnh cũ */

            // Khởi tạo một đối tượng mới chỉ với các thuộc tính cơ bản, đảm bảo cấu trúc tối thiểu
            const cleanTrait = {
                name: trait.name,
                desc: trait.desc,
                effects: trait.effects,
                bonus: trait.bonus,
                rarity: trait.rarity
            };

            // Kiểm tra và thêm các thuộc tính mở rộng nếu chúng tồn tại trong dữ liệu gốc
            // Điều này cho phép AI đọc được thông tin cần thiết để khởi tạo hệ thống
            if (trait.resources) {
                cleanTrait.resources = trait.resources;
            }
            if (trait.next_upgrade_functions) {
                cleanTrait.next_upgrade_functions = trait.next_upgrade_functions;
            }
            return cleanTrait;			
        }

