                "2": `Phàm Nhân|${birthName}`,
                "3": "Chưa xác định", "4": "Mọi thứ bình thường", "5": "Chưa xác định", "6": "Chưa xác định", "7": "Chưa xác định", "8": "Chưa xác định",
                "9": playerRemarks,
