        function updateRedDots() {
            const buttonsToTrack = [
                'fullscreen-btn',
                'surrounding-characters-button',
                'summary-log-button',
                'manage-log-button',
                'snapshot-btn',
                'system-settings-button'
            ];
            buttonsToTrack.forEach(id => {
                const button = document.getElementById(id);
                if (button) {
                    let dot = button.querySelector('.red-dot');
                    if (!seenFeatures[id] && id !== 'surrounding-characters-button') { // Loại trừ nút nhân vật khỏi logic này
                        if (!dot) {
                            dot = document.createElement('span');
                            dot.className = 'red-dot';
                            button.appendChild(dot);
                        }
                    } else {
                        if (dot && id !== 'surrounding-characters-button') {
                            dot.remove();
                        }
                    }
                }
            });
        }

