                switch(action) {
                    case 'create': openCustomBirthEditor(); break;
                    case 'import': handleImportCustomData(CUSTOM_BIRTHS_KEY, 'Xuất thân'); break;
                    case 'export': handleExportCustomData(CUSTOM_BIRTHS_KEY, 'custom_births.json'); break;
