                    listEl: document.getElementById('custom-race-selection-list'),
                    dbKey: CUSTOM_RACES_KEY,
                    openEditor: openCustomRaceEditor,
                }
            };
            const { overlay, listEl, dbKey, openEditor } = config[type];
            const items = await dbGet(dbKey) || [];

            listEl.innerHTML = '';
            if (items.length === 0) {
                listEl.innerHTML = `<p style="text-align:center; opacity:0.7;">Danh sách trống, vui lòng tạo trước.</p>`;
            } else {
                items.forEach(item => {
                    const div = document.createElement('div');
                    div.className = 'custom-list-item';
                    div.innerHTML = `
                        <span class="item-name">${item.tag}</span>
                        <div class="item-actions">
                            <button data-id="${item.id}" data-action="edit" title="Chỉnh Sửa"><i class="fas fa-edit"></i></button>
                            <button data-id="${item.id}" data-action="delete" title="Xóa"><i class="fas fa-trash"></i></button>
                        </div>
                    `;
                    div.querySelector('.item-name').addEventListener('click', async () => {
                        const currentRemaining = calculateRemainingPoints();
                        const oldCost = creationState[type === 'birth' ? 'selectedBirth' : 'selectedRace'] ? CREATION_CONFIG[type === 'birth' ? 'BIRTHS' : 'RACES']['Tự Định Nghĩa'].cost : 0;
                        const newCost = CREATION_CONFIG[type === 'birth' ? 'BIRTHS' : 'RACES']['Tự Định Nghĩa'].cost;

                        if (currentRemaining + oldCost < newCost) {
                            await showCustomAlert('Điểm thuộc tính không đủ, không thể chọn mục này!');
                            return;
                        }

                        creationState[type === 'birth' ? 'selectedBirth' : 'selectedRace'] = 'Tự Định Nghĩa';
                        creationState[type === 'birth' ? 'customBirth' : 'customRace'] = item;
                        overlay.classList.remove('visible');
                        renderCreationStep();
                    });
                    listEl.appendChild(div);
                });
            }

            listEl.querySelectorAll('button').forEach(btn => {
                btn.addEventListener('click', async (e) => {
                    e.stopPropagation();
                    const id = e.currentTarget.dataset.id;
                    const action = e.currentTarget.dataset.action;
                    if (action === 'edit') {
                        openEditor(id);
                    } else if (action === 'delete') {
                        if (await showCustomConfirm('Ngươi có chắc chắn muốn xóa mục tùy chỉnh này không?')) {
                            let data = await dbGet(dbKey) || [];
                            data = data.filter(item => item.id !== id);
                            await dbSet(dbKey, data);
                            await openCustomDataSelection(type);
                        }
                    }
                });
            });

            overlay.classList.add('visible');
        }

        async function openCustomBirthEditor(id = null) {
            currentEditingCustomBirthId = id;
