        function getWarehouseCapacity() {
            const realm = currentPlayerData.realm || '';
            if (realm.includes('Luyện Khí')) return 1;
            if (realm.includes('Trúc Cơ')) return 2;
            if (realm.includes('Kết Đan') || realm.includes('Kim Đan')) return 3;
            if (realm.includes('Nguyên Anh')) return 4;
            if (realm.includes('Hóa Thần')) return 5;
            if (realm.includes('Luyện Hư')) return 6;
            if (realm.includes('Hợp Thể')) return 7;
            if (realm.includes('Đại Thừa')) return 8;
            return 1;
        }

