        async function handleAIGenRequest(prompt, isAuto = false) {
            if (typeof eventEmit !== 'function' || typeof eventOn !== 'function') {
                if (!isAuto) await showCustomAlert('Lỗi: Không tìm thấy giao diện giao tiếp tiện ích Tampermonkey (eventEmit/eventOn).');
                return;
            }

            const width = parseInt(document.getElementById('ai-gen-width').value);
            const height = parseInt(document.getElementById('ai-gen-height').value);
            const statusEl = document.getElementById('ai-gen-status');

            if (!prompt) {
                if (!isAuto) statusEl.textContent = 'Prompt không được để trống!';
                return;
            }

            const requestId = `bg_${Date.now()}`;
            const requestData = { id: requestId, prompt, width, height, type: 1 };

            if (!isAuto) statusEl.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Đang gửi yêu cầu...';
            else showDanmaku('Phát hiện lệnh tạo ảnh, bắt đầu tự động tạo...', 'world');

            eventEmit('generate_image_request', requestData);

            const responseListener = (responseData) => {
                if (responseData.id === requestId) {
                    if (responseData.success && responseData.imageData) {
                        if (!isAuto) statusEl.textContent = 'Tạo thành công! Đang lưu...';
                        db.backgrounds.add({ data: responseData.imageData }).then(newId => {
                            chatBackgroundSettings.activeBackgroundId = newId;
                            applyChatBackground();
                            renderBackgroundThumbnails();
                            if (!isAuto) {
                                statusEl.textContent = 'Nền đã được đặt!';
                                setTimeout(() => aiImageGenOverlay.classList.remove('visible'), 1000);
                            } else {
                                showDanmaku('Tự động tạo ảnh hoàn tất, nền đã được cập nhật!', 'world');
                            }
                        }).catch(err => {
                            if (!isAuto) statusEl.textContent = `Lưu thất bại: ${err.message}`;
                        });
                    } else {
                        if (!isAuto) statusEl.textContent = `Tạo thất bại: ${responseData.error || 'Lỗi không xác định'}`;
                        else showDanmaku(`Tự động tạo ảnh thất bại: ${responseData.error || 'Lỗi không xác định'}`, 'error');
                    }
                    // Dọn dẹp listener
                    if (window.removeEventOn) removeEventOn('generate_image_response', responseListener);
                }
            };
            eventOn('generate_image_response', responseListener);
        }

        async function handleBatchDeleteClick() {
const modal = document.getElementById('chat-background-settings-modal');
const btn = document.getElementById('batch-delete-background-btn');

// Nếu hiện đang ở chế độ xóa, thì thực hiện logic xóa
