        function renderAchievementReqDetails(requirement = {}) {
            const type = document.getElementById('ca-editor-req-type').value;
            const container = document.getElementById('ca-editor-req-details');
            container.innerHTML = '';

            switch(type) {
                case 'player_attr':
                    const attrSelect = document.createElement('select');
                    Object.keys(CREATION_CONFIG.ATTRIBUTES).forEach(attr => {
                        const option = document.createElement('option');
                        option.value = attr;
                        option.textContent = attr;
                        attrSelect.appendChild(option);
                    });
                    if (requirement.key) attrSelect.value = requirement.key;

                    const valueInput = document.createElement('input');
                    valueInput.type = 'number';
                    valueInput.placeholder = 'Giá trị mục tiêu';
                    valueInput.value = requirement.value || '';

                    container.append(attrSelect, valueInput);
                    break;
                case 'ai_response':
                    const keywordInput = document.createElement('input');
                    keywordInput.type = 'text';
                    keywordInput.placeholder = 'Từ khóa';
                    keywordInput.value = requirement.keyword || '';
                    container.appendChild(keywordInput);
                    break;
                case 'variable':
                    const tableSelect = document.createElement('select');
                    tableSelect.innerHTML = `
                        <option value="0">Nhân Vật(0)</option>
                        <option value="1">Vật Phẩm(1)</option>
                        <option value="6">Nhiệm Vụ(6)</option>
                        <option value="7">Linh Thú(7)</option>
                        <option value="8">Kỹ Năng(8)</option>
                    `;
                    if (requirement.table) tableSelect.value = requirement.table;

                    const idInput = document.createElement('input');
                    idInput.type = 'text';
                    idInput.placeholder = 'ID dòng (ví dụ: B1)';
                    idInput.value = requirement.id || '';

                    const colInput = document.createElement('input');
                    colInput.type = 'number';
                    colInput.placeholder = 'Số cột';
                    colInput.min = 0;
                    colInput.value = requirement.col || '';

                    const varValueInput = document.createElement('input');
                    varValueInput.type = 'text';
                    varValueInput.placeholder = 'Giá trị chứa';
                    varValueInput.value = requirement.value || '';

                    container.append(tableSelect, idInput, colInput, varValueInput);
                    break;
            }
        }

        function renderAchievementRewardDetails(reward = {}) {
            const type = document.getElementById('ca-editor-reward-type').value;
            const container = document.getElementById('ca-editor-reward-details');
            container.innerHTML = '';

            if (type === 'none') return;

            const createInput = (placeholder, value = '') => {
                const input = document.createElement('input');
                input.type = 'text';
                input.placeholder = placeholder;
                input.value = value;
                return input;
            };

            switch(type) {
                case 'item':
                    container.append(
                        createInput('ID Vật Phẩm (bắt đầu bằng I)', reward.id), createInput('Tên', reward.name), createInput('Mô Tả', reward.desc),
                        createInput('Loại', reward.itemType), createInput('Hiệu Quả', reward.effect), createInput('Số Lượng', reward.quantity || 1)
                    );
                    break;
                case 'character':
                    container.append(
                        createInput('ID nhân vật (bắt đầu bằng C)', reward.id), createInput('Tên|Giới Tính', reward.nameGender), createInput('Cảnh Giới|Thân Phận', reward.realmIdentity)
                    );
                    break;
                case 'skill':
                    container.append(
                        createInput('ID kỹ năng (bắt đầu bằng S)', reward.id), createInput('Tên', reward.name), createInput('Cấp', reward.level)
                    );
                    break;
                case 'beast':
                     container.append(
                        createInput('ID linh thú (bắt đầu bằng P)', reward.id), createInput('Tên', reward.name), createInput('Cấp', reward.level)
                    );
                    break;
                case 'task':
                    container.append(
                        createInput('ID nhiệm vụ (bắt đầu bằng T)', reward.id), createInput('Tiêu Đề', reward.title), createInput('Mô Tả', reward.desc),
                        createInput('Phần Thưởng', reward.reward), createInput('Hình phạt', reward.punishment), createInput('Độ Khó', reward.difficulty)
                    );
                    break;
                case 'world_event':
                    container.append(
                        createInput('Thời Gian', reward.time), createInput('Địa Điểm', reward.location), createInput('Mô Tả Sự Kiện', reward.desc)
                    );
                    break;
            }
        }

        async function saveCustomAchievement() {
            const name = document.getElementById('ca-editor-name').value.trim();
            if (!name) { await showCustomAlert('Tên thành tựu không được để trống!'); return; }

            const reqType = document.getElementById('ca-editor-req-type').value;
            const reqDetails = document.getElementById('ca-editor-req-details').children;
            let requirement = { type: reqType };
            switch(reqType) {
                case 'player_attr':
                    requirement.key = reqDetails[0].value;
                    requirement.value = reqDetails[1].value;
                    break;
                case 'ai_response':
                    requirement.keyword = reqDetails[0].value;
                    break;
                case 'variable':
                    requirement.table = reqDetails[0].value;
                    requirement.id = reqDetails[1].value;
                    requirement.col = reqDetails[2].value;
                    requirement.value = reqDetails[3].value;
                    break;
            }

            const rewardType = document.getElementById('ca-editor-reward-type').value;
            const rewardDetails = document.getElementById('ca-editor-reward-details').children;
            let reward = { type: rewardType };
            let rewardCommand = '';

            if (rewardType !== 'none') {
                try {
                    switch(rewardType) {
                        case 'item':
                            reward = { ...reward, id: rewardDetails[0].value, name: rewardDetails[1].value, desc: rewardDetails[2].value, itemType: rewardDetails[3].value, effect: rewardDetails[4].value, quantity: rewardDetails[5].value };
                            rewardCommand = `set(${JSON.stringify({"0":reward.id, "1":reward.name, "2":reward.itemType, "3":reward.desc, "4":reward.effect, "5":reward.quantity})})`;
                            break;
                        case 'character':
                            reward = { ...reward, id: rewardDetails[0].value, nameGender: rewardDetails[1].value, realmIdentity: rewardDetails[2].value };
                            rewardCommand = `set(${JSON.stringify({"0":reward.id, "1":reward.nameGender, "2":reward.realmIdentity})})`;
                            break;
                        case 'skill':
                            reward = { ...reward, id: rewardDetails[0].value, name: rewardDetails[1].value, level: rewardDetails[2].value };
                            rewardCommand = `set(${JSON.stringify({"0":reward.id, "1":reward.name, "2":reward.level})})`;
                            break;
                        case 'beast':
                             reward = { ...reward, id: rewardDetails[0].value, name: rewardDetails[1].value, level: rewardDetails[2].value };
                            rewardCommand = `set(${JSON.stringify({"0":reward.id, "1":reward.name, "2":reward.level})})`;
                            break;
                        case 'task':
                            reward = { ...reward, id: rewardDetails[0].value, title: rewardDetails[1].value, desc: rewardDetails[2].value, reward: rewardDetails[3].value, punishment: rewardDetails[4].value, difficulty: rewardDetails[5].value };
                            rewardCommand = `set(${JSON.stringify({"0":reward.id, "1":reward.title, "2":reward.desc, "3":reward.reward, "4":reward.punishment, "5":reward.difficulty})})`;
                            break;
                        case 'world_event':
                            reward = { ...reward, time: rewardDetails[0].value, location: rewardDetails[1].value, desc: rewardDetails[2].value };
                            rewardCommand = `addWorldEvent("${reward.time}", "${reward.location}", "${reward.desc}")`;
                            break;
                    }
                } catch(e) {
                    await showCustomAlert('Thông tin phần thưởng sai định dạng, vui lòng kiểm tra.');
                    return;
                }
            }

            const achievementData = {
                id: currentEditingAchievementId || crypto.randomUUID(),
                name: name,
                description: document.getElementById('ca-editor-desc').value.trim(),
                completionText: document.getElementById('ca-editor-completion-text').value.trim(),
                quality: document.getElementById('ca-editor-quality').value,
                requirement: requirement,
                reward: rewardType !== 'none' ? { ...reward, command: rewardCommand } : null
            };

            const archive = await db.archives.get(currentArchiveName);
            const customAchievements = archive.data.state.achievements.custom || [];
            if (currentEditingAchievementId) {
                const index = customAchievements.findIndex(a => a.id === currentEditingAchievementId);
                customAchievements[index] = achievementData;
            } else {
                customAchievements.push(achievementData);
            }
            archive.data.state.achievements.custom = customAchievements;
            await db.archives.put(archive);

            customAchievementEditorOverlay.classList.remove('visible');
            await openCustomAchievementManager();
        }

        async function checkAchievements(aiResponse) {
            const archive = await db.archives.get(currentArchiveName);
            if (!archive || !archive.data.state.achievements) return;

            const { completed, custom } = archive.data.state.achievements;
            const uncompleted = custom.filter(ach => !completed.includes(ach.id));

            let changed = false;
            for (const ach of uncompleted) {
                let isCompleted = false;
                const req = ach.requirement;
                switch (req.type) {
                    case 'player_attr':
                        const attrValue = currentPlayerData.detailedAttributes[req.key]?.current || 0;
                        if (attrValue >= parseInt(req.value)) isCompleted = true;
                        break;
                    case 'ai_response':
                        if (aiResponse.includes(req.keyword)) isCompleted = true;
                        break;
                    case 'variable':
                        try {
                            const value = currentState[req.table]?.[req.id]?.[req.col];
                            if (typeof value === 'string' && value.includes(req.value)) isCompleted = true;
                        } catch (e) { /* Ignore errors from invalid paths */ }
                        break;
                }

                if (isCompleted) {
                    completed.push(ach.id);
                    changed = true;
                    const danmakuTypeMap = {
						'Tầm Thường': 'npc', 'Phổ Thông': 'player', 'Sử Thi': 'item',
						'Truyền Thuyết': 'world', 'Thần Tích': 'error'
                    };
                    const danmakuType = danmakuTypeMap[ach.quality] || 'world';
                    showDanmaku(`Hoàn thành thành tựu: ${ach.completionText || ach.name}`, danmakuType);

                    if (ach.reward && ach.reward.command) {
                        showDanmaku(`Phần thưởng thành tựu: ${ach.reward.description || 'Đã phát'}`, 'item');
                        const { delta } = parseTableEditCommands(ach.reward.command);
                        currentState = applyChanges(currentState, delta);
                        syncStateFromTables();

                        // Buộc làm mới tất cả các giao diện người dùng có thể bị ảnh hưởng
                        renderInventory(inventoryItems);
                        renderPlayerAttributes(currentPlayerData);
                        // Nếu có các giao diện người dùng khác có thể bị ảnh hưởng bởi thành tựu, cũng gọi hàm kết xuất của chúng ở đây
                        // Ví dụ, nếu thành tựu có thể thêm kỹ năng hoặc linh thú:
                        // openSkillsOverlay(); // Làm mới chế độ xem kỹ năng (nếu đang mở)
                        // showSpiritBeastListView(); // Làm mới danh sách linh thú (nếu đang mở)
                    }
                }
            }

            if (changed) {
                archive.data.state.achievements.completed = completed;
                await db.archives.put(archive);
            }
        }

