        class MapRenderer {
            constructor(canvas, mapData, onSelectCallback, isWorldMap = false, isEditor = false) {
                this.canvas = canvas;
                this.ctx = canvas.getContext('2d');
                this.mapData = mapData;
                this.onSelectCallback = onSelectCallback;
                this.isWorldMap = isWorldMap;
                this.isEditor = isEditor;
                this.infoPanel = document.getElementById(isWorldMap && !isEditor ? 'world-map-info-panel' : 'map-info-panel');
                this.container = this.canvas.parentElement;
                this.scale = 1;
                this.offsetX = 0;
                this.offsetY = 0;
                this.isDragging = false;
                this.lastX = 0;
                this.lastY = 0;
                this.hoveredRegion = null;
                this.selectedPoint = null;
                this.selectedRegionInfo = null;
                this.longPressTimer = null;
                this.playerData = null;
				this.characters = [];
                this.playerBlinkState = true;
                this.editingItem = null;
                this.mode = 'view'; // 'view', 'draw_polygon', 'place_poi'
                this.tempPoints = [];
                this.init();
            }

            setMapData(newMapData) {
                this.mapData = newMapData;
                this.drawMap();
            }

            setEditingItem(item) {
                this.editingItem = item;
                this.drawMap();
            }

            setMode(newMode) {
                this.mode = newMode;
                this.canvas.style.cursor = (newMode === 'view') ? 'grab' : 'crosshair';
                this.drawMap();
            }

            init() {
                this.resize();
                window.addEventListener('resize', () => this.resize());
                this.canvas.addEventListener('mousedown', (e) => this.onMouseDown(e));
                this.canvas.addEventListener('mousemove', (e) => this.onMouseMove(e));
                this.canvas.addEventListener('mouseup', (e) => this.onMouseUp(e));
                this.canvas.addEventListener('mouseleave', () => { this.isDragging = false; });
                this.canvas.addEventListener('click', (e) => this.onClick(e));
                this.canvas.addEventListener('contextmenu', (e) => {
                    e.preventDefault();
                    if (this.isEditor && this.mode === 'draw_polygon') {
                        this.setMode('view');
                        document.getElementById('map-editor-status').textContent = 'Vẽ hoàn tất. Vui lòng lưu thay đổi.';
                    } else {
                        this.clearSelection();
                    }
                });
                this.canvas.addEventListener('touchstart', (e) => {
                    e.preventDefault();
                    this.longPressTimer = setTimeout(() => {
                        if (this.isEditor && this.mode === 'draw_polygon') {
                            this.setMode('view');
                            document.getElementById('map-editor-status').textContent = 'Vẽ hoàn tất. Vui lòng lưu thay đổi.';
                        } else {
                            this.clearSelection();
                        }
                        this.longPressTimer = null;
                    }, 500);
                    this.onMouseDown(e.touches[0]);
                }, { passive: false });
                this.canvas.addEventListener('touchmove', (e) => {
                    e.preventDefault();
                    clearTimeout(this.longPressTimer);
                    this.onMouseMove(e.touches[0]);
                }, { passive: false });
                this.canvas.addEventListener('touchend', (e) => {
                    clearTimeout(this.longPressTimer);
                    if (this.longPressTimer !== null) {
                        this.onClick(e.changedTouches[0]);
                    }
                    this.onMouseUp(e.changedTouches[0]);
                });

                if (this.isWorldMap) {
                    setInterval(() => {
                        this.playerBlinkState = !this.playerBlinkState;
                        this.drawMap();
                    }, 500);
                }
            }

            zoom(factor) {
                const newScale = Math.max(0.1, Math.min(3, this.scale * factor));
                const centerX = (this.canvas.width / 2 - this.offsetX) / this.scale;
                const centerY = (this.canvas.height / 2 - this.offsetY) / this.scale;
                this.offsetX = this.canvas.width / 2 - centerX * newScale;
                this.offsetY = this.canvas.height / 2 - centerY * newScale;
                this.scale = newScale;
                this.drawMap();
            }

            setPlayerData(playerData) { this.playerData = playerData; }
			setCharacters(chars) { this.characters = chars; }
            clearSelection() {
                this.selectedPoint = null;
                this.selectedRegionInfo = null;
                this.drawMap();
                if (this.infoPanel) this.updateInfoPanel();
            }
            resize() {
                this.canvas.width = this.container.clientWidth;
                this.canvas.height = this.container.clientHeight;
                this.drawMap();
            }

            drawMap() {
                this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
                this.ctx.save();
                this.ctx.translate(this.offsetX, this.offsetY);
                this.ctx.scale(this.scale, this.scale);

                this.mapData.main_regions.forEach(mainRegion => {
                    this.ctx.fillStyle = hexToRgba(mainRegion.color || '#C8B89A', 0.7);
                    this.drawNaturalPath(mainRegion.points);
                    this.ctx.fill();
                });

                this.mapData.main_regions.forEach(mainRegion => {
                    this.ctx.save(); // Lưu trạng thái, chuẩn bị cắt
                    this.drawNaturalPath(mainRegion.points);
                    this.ctx.clip(); // Áp dụng cắt

                    const subs = this.mapData.sub_regions.filter(sub => sub.main_region === mainRegion.name);
                    subs.forEach(subRegion => {
                        // 3a. Tô màu khu vực phụ (hiện có thể che phủ chính xác màu khu vực chính)
                        this.ctx.fillStyle = hexToRgba(subRegion.color || '#8D6E63', 0.85); // Tăng độ mờ để đảm bảo che phủ
                        this.drawNaturalPath(subRegion.points);
                        this.ctx.fill();

                        // 3b. Vẽ đường viền nét đứt của khu vực phụ trong vùng đã cắt
                        this.ctx.strokeStyle = '#654321';
                        this.ctx.lineWidth = 1.5 / this.scale;
                        this.ctx.setLineDash([8 / this.scale, 4 / this.scale]);
                        this.ctx.stroke();
                        this.ctx.setLineDash([]);
                    });

                    this.ctx.restore(); // Khôi phục trạng thái, xóa vùng cắt
                });

                // Lớp 4: Đánh dấu khu vực đang chỉnh sửa
                if (this.isEditor && this.editingItem && this.editingItem.points) {
                    this.ctx.fillStyle = 'rgba(255, 255, 0, 0.3)';
                    this.drawNaturalPath(this.editingItem.points);
                    this.ctx.fill();
                }

                // Lớp 5: Vẽ đường viền liền nét cho tất cả các lãnh thổ chính
                this.ctx.strokeStyle = '#654321';
                this.ctx.lineWidth = 3 / this.scale;
                this.mapData.main_regions.forEach(region => {
                    this.drawNaturalPath(region.points);
                    this.ctx.stroke();
                });

                // Lớp 6: Vẽ tất cả các nhãn và điểm ưa thích
                this.ctx.shadowColor = 'rgba(255, 255, 255, 0.7)';
                this.ctx.shadowBlur = 5;
                this.mapData.main_regions.forEach(region => {
                    const center = this.getPolygonCenter(region.points);
                    this.ctx.font = `bold ${24 / this.scale}px 'ZCOOL XiaoWei', serif`;
                    this.ctx.fillStyle = '#4a3f35';
                    this.ctx.textAlign = 'center';
                    this.ctx.fillText(region.name, center.x, center.y);
                });
                this.mapData.sub_regions.forEach(region => {
                    const center = this.getPolygonCenter(region.points);
                    this.ctx.font = `${16 / this.scale}px 'Noto Serif SC', serif`;
                    this.ctx.fillStyle = '#4a3f35';
                    this.ctx.fillText(region.name, center.x, center.y);
                });
                this.ctx.shadowBlur = 0;

                this.mapData.points_of_interest.forEach(poi => {
                    this.ctx.beginPath();
                    this.ctx.arc(poi.x, poi.y, 5 / this.scale, 0, 2 * Math.PI);
                    this.ctx.fillStyle = (this.isEditor && this.editingItem && this.editingItem.name === poi.name) ? 'rgba(255, 255, 0, 0.8)' : '#D4AF37';
                    this.ctx.fill();
                    this.ctx.strokeStyle = '#000';
                    this.ctx.lineWidth = 1 / this.scale;
                    this.ctx.stroke();

                    this.ctx.font = `${12 / this.scale}px 'Noto Serif SC', serif`;
                    this.ctx.textAlign = 'center';

                    this.ctx.strokeStyle = '#4a3f35'; // Sử dụng màu nâu sẫm nhất quán với nhãn lãnh thổ chính làm đường viền
                    this.ctx.lineWidth = 2.5 / this.scale; // Độ rộng nét viền
                    this.ctx.strokeText(poi.name, poi.x, poi.y - 10 / this.scale);

                    this.ctx.fillStyle = '#f5f5dc'; // Sử dụng màu be/giấy da mềm mại để tô màu
                    this.ctx.fillText(poi.name, poi.x, poi.y - 10 / this.scale);
                });

                if (this.isEditor && this.tempPoints.length > 0) {
                    this.ctx.fillStyle = 'rgba(255, 0, 0, 0.5)';
                    this.ctx.strokeStyle = 'rgba(255, 255, 255, 0.8)';
                    this.ctx.lineWidth = 2 / this.scale;
                    if (this.mode === 'draw_polygon') {
                        this.ctx.beginPath();
                        this.ctx.moveTo(this.tempPoints[0][0], this.tempPoints[0][1]);
                        for (let i = 1; i < this.tempPoints.length; i++) {
                            this.ctx.lineTo(this.tempPoints[i][0], this.tempPoints[i][1]);
                        }
                        this.ctx.stroke();
                    }
                    this.tempPoints.forEach(p => {
                        this.ctx.beginPath();
                        this.ctx.arc(p[0], p[1], 5 / this.scale, 0, 2 * Math.PI);
                        this.ctx.fill();
                    });
                }

                if (this.selectedPoint) {
                    this.ctx.beginPath();
                    this.ctx.arc(this.selectedPoint.x, this.selectedPoint.y, 8 / this.scale, 0, 2 * Math.PI);
                    this.ctx.fillStyle = 'rgba(255, 0, 0, 0.7)';
                    this.ctx.strokeStyle = '#fff';
                    this.ctx.lineWidth = 2 / this.scale;
                    this.ctx.fill();
                    this.ctx.stroke();
                }

				// 【Chỉnh sửa cốt lõi】Vẽ tất cả NPC trước khi vẽ người chơi
				if (this.isWorldMap && this.characters) {
				  this.characters.forEach(char => {
					if (char.coordinates && char.id !== 'B1') { // Đảm bảo có tọa độ và không phải chính người chơi
					  const [x, y] = char.coordinates;

					  // Vẽ điểm đánh dấu
					  this.ctx.fillStyle = 'rgba(138, 43, 226, 0.9)'; // Đánh dấu màu tím
					  this.ctx.strokeStyle = '#FFFFFF';
					  this.ctx.lineWidth = 1.5 / this.scale;
					  this.ctx.beginPath();
					  this.ctx.arc(x, y, 6 / this.scale, 0, 2 * Math.PI);
					  this.ctx.fill();
					  this.ctx.stroke();

					  // Vẽ tên
					  this.ctx.font = `bold ${12 / this.scale}px 'Noto Serif SC', serif`;
					  this.ctx.textAlign = 'center';
					  this.ctx.strokeStyle = 'rgba(0,0,0,0.8)';
					  this.ctx.lineWidth = 3 / this.scale;
					  this.ctx.strokeText(char.name, x, y + 20 / this.scale);
					  this.ctx.fillStyle = '#FFD700'; // Tên màu vàng kim
					  this.ctx.fillText(char.name, x, y + 20 / this.scale);
					}
				  });
				}				

                if (this.isWorldMap && this.playerData && this.playerData.fullLocationString) {
					const locationString = this.playerData.fullLocationString;
					const coordMatch = locationString.match(/\d+,\d+/);

					if (coordMatch) {
					const coords = coordMatch[0].split(',').map(Number);
                        if (coords.length === 2 && !isNaN(coords[0]) && !isNaN(coords[1])) {
                            this.ctx.fillStyle = this.playerBlinkState ? 'rgba(0, 255, 0, 0.9)' : 'rgba(0, 128, 0, 0.7)';
                            this.ctx.beginPath();
                            this.ctx.arc(coords[0], coords[1], 8 / this.scale, 0, 2 * Math.PI);
                            this.ctx.fill();
                            this.ctx.strokeStyle = '#fff';
                            this.ctx.lineWidth = 2 / this.scale;
                            this.ctx.stroke();
                        }
                    }
                }

                this.ctx.restore();
                if (this.isWorldMap) this.drawScaleRuler();
            }
            drawScaleRuler() {
                const rulerLengthPx = 100;
                const rulerLengthMeters = rulerLengthPx * 10000 / this.scale;
                const rulerText = rulerLengthMeters > 10000000 ? `${Math.round(rulerLengthMeters / 1000)} vạn dặm` : `${Math.round(rulerLengthMeters / 1000)} km`;
                this.ctx.save();
                this.ctx.fillStyle = 'rgba(0,0,0,0.6)';
                this.ctx.fillRect(20, this.canvas.height - 40, rulerLengthPx + 20, 30);
                this.ctx.strokeStyle = '#fff';
                this.ctx.lineWidth = 2;
                this.ctx.beginPath();
                this.ctx.moveTo(30, this.canvas.height - 25);
                this.ctx.lineTo(30 + rulerLengthPx, this.canvas.height - 25);
                this.ctx.moveTo(30, this.canvas.height - 30);
                this.ctx.lineTo(30, this.canvas.height - 20);
                this.ctx.moveTo(30 + rulerLengthPx, this.canvas.height - 30);
                this.ctx.lineTo(30 + rulerLengthPx, this.canvas.height - 20);
                this.ctx.stroke();
                this.ctx.fillStyle = '#fff';
                this.ctx.font = '12px Noto Serif SC, serif';
                this.ctx.textAlign = 'center';
                this.ctx.fillText(rulerText, 30 + rulerLengthPx / 2, this.canvas.height - 28);
                this.ctx.restore();
            }

            drawNaturalPath(points) {
                if (!points || points.length < 2) return;

                // Gọi hàm tạo ranh giới mới
                const detailedPoints = generateNaturalBoundaryPoints(points);

                if (detailedPoints.length < 2) return;

                this.ctx.beginPath();
                this.ctx.moveTo(detailedPoints[0][0], detailedPoints[0][1]);
                for (let i = 1; i < detailedPoints.length; i++) {
                    this.ctx.lineTo(detailedPoints[i][0], detailedPoints[i][1]);
                }
                this.ctx.closePath();
            }

            getPolygonCenter(points) {
                if (!points || points.length === 0) return {x: 0, y: 0};
                let x = 0, y = 0;
                points.forEach(p => { x += p[0]; y += p[1]; });
                return { x: x / points.length, y: y / points.length };
            }

            isPointInPolygon(point, vs) {
                let x = point.x, y = point.y;
                let inside = false;
                for (let i = 0, j = vs.length - 1; i < vs.length; j = i++) {
                    let xi = vs[i][0], yi = vs[i][1];
                    let xj = vs[j][0], yj = vs[j][1];
                    let intersect = ((yi > y) !== (yj > y)) && (x < (xj - xi) * (y - yi) / (yj - yi) + xi);
                    if (intersect) inside = !inside;
                }
                return inside;
            }

            getMousePos(evt) {
                const rect = this.canvas.getBoundingClientRect();
                return {
                    x: (evt.clientX - rect.left - this.offsetX) / this.scale,
                    y: (evt.clientY - rect.top - this.offsetY) / this.scale
                };
            }

            onMouseDown(e) {
                this.isDragging = false;
                this.dragStartPos = { x: e.clientX, y: e.clientY };
                this.lastX = e.clientX;
                this.lastY = e.clientY;
                if (this.isEditor && this.mode === 'view') {
                    this.canvas.style.cursor = 'grabbing';
                }
            }

            onMouseMove(e) {
                if (this.dragStartPos) {
                    const dx = e.clientX - this.dragStartPos.x;
                    const dy = e.clientY - this.dragStartPos.y;
                    if (Math.sqrt(dx*dx + dy*dy) > 5) { this.isDragging = true; }
                }
                if (this.isDragging) {
                    const dx = e.clientX - this.lastX;
                    const dy = e.clientY - this.lastY;
                    this.offsetX += dx;
                    this.offsetY += dy;
                    this.lastX = e.clientX;
                    this.lastY = e.clientY;
                    this.drawMap();
                } else if (!this.selectedPoint && this.infoPanel) {
                    this.updateInfoPanel(this.getMousePos(e));
                }
            }

            onMouseUp(e) {
                this.dragStartPos = null;
                if (this.isEditor && this.mode === 'view') {
                    this.canvas.style.cursor = 'grab';
                }
            }

            onClick(e) {
                if (this.isDragging) { this.isDragging = false; return; }
                const pos = this.getMousePos(e);


				if (this.isWorldMap && this.characters) {
				  const charClickRadius = 8 / this.scale;
				  for (const char of this.characters) {
					if (char.coordinates && char.id !== 'B1') {
					  const [cx, cy] = char.coordinates;
					  if (Math.sqrt(Math.pow(pos.x - cx, 2) + Math.pow(pos.y - cy, 2)) < charClickRadius) {
						worldMapOverlay.classList.remove('visible'); // Đóng bản đồ
						openCharactersOverlay(); // Mở danh sách nhân vật (overlay)

						// Chuyển thẳng đến và hiển thị chi tiết nhân vật đó
						showCharacterDetailPanel(char, null);
						characterListView.classList.add('hidden');
						characterDetailView.classList.remove('hidden');
						return; // Kết thúc xử lý sự kiện click
					  }
					}
				  }
				}				

                if (this.isEditor) {
                    if (this.mode === 'draw_polygon') {
                        this.tempPoints.push([Math.round(pos.x), Math.round(pos.y)]);
                        this.drawMap();
                        return;
                    }
                    if (this.mode === 'place_poi') {
                        this.tempPoints = [[Math.round(pos.x), Math.round(pos.y)]];
                        this.setMode('view');
                        document.getElementById('map-editor-status').textContent = 'Đặt hoàn tất. Vui lòng lưu thay đổi.';
                        return;
                    }
                }

                this.selectedPoint = pos;
                let locationString = "Vùng đất vô danh";
                let mainRegion = null, subRegion = null, poi = null;
                const poiRadius = 10 / this.scale;
                for (const p of this.mapData.points_of_interest) {
                    if (Math.sqrt(Math.pow(pos.x - p.x, 2) + Math.pow(pos.y - p.y, 2)) < poiRadius) {
                        poi = p; break;
                    }
                }
                if (poi) {
                    mainRegion = this.mapData.main_regions.find(r => r.name === poi.main_region);
                    subRegion = this.mapData.sub_regions.find(r => r.name === poi.sub_region);
                } else {
                    let smallestArea = Infinity, foundRegion = null;
                    [...this.mapData.sub_regions, ...this.mapData.main_regions].forEach(region => {
                        if (this.isPointInPolygon(pos, region.points)) {
                            const area = this.getPolygonArea(region.points);
                            if (area < smallestArea) { smallestArea = area; foundRegion = region; }
                        }
                    });
                    if (foundRegion) {
                        if (this.mapData.sub_regions.includes(foundRegion)) {
                            subRegion = foundRegion;
                            mainRegion = this.mapData.main_regions.find(r => r.name === subRegion.main_region);
                        } else { mainRegion = foundRegion; }
                    }
                }
                if (mainRegion) {
                    locationString = subRegion ? `${mainRegion.name}/${subRegion.name}` : mainRegion.name;
                    if (poi) locationString += `|(${poi.name}) `;
                }
                const finalLocation = `${locationString}|${Math.round(pos.x)},${Math.round(pos.y)}`;
                this.selectedRegionInfo = { locationString, finalLocation, mainRegion, subRegion, poi };
                if (this.infoPanel) this.updateInfoPanel();
                this.drawMap();
            }

            getPolygonArea(points) {
                if (!points) return Infinity;
                let area = 0;
                for (let i = 0, j = points.length - 1; i < points.length; j = i++) {
                    area += (points[j][0] + points[i][0]) * (points[j][1] - points[i][1]);
                }
                return Math.abs(area / 2);
            }

            updateInfoPanel(mousePos = null) {
                if (!this.infoPanel) return;
                if (this.selectedRegionInfo) {
                    const { locationString, finalLocation, mainRegion, subRegion, poi } = this.selectedRegionInfo;
                    let description = mainRegion ? mainRegion.description : '';
                    if (subRegion) description += `<br><br><strong>${subRegion.name}:</strong> ${subRegion.description}`;
                    if (poi) description += `<br><br><strong>${poi.name}:</strong> ${poi.description}`;
                    let distanceText = '', distance = 0;
                    if (this.isWorldMap && this.playerData && this.playerData.fullLocationString) {
						const locationString = this.playerData.fullLocationString;
						const coordMatch = locationString.match(/\d+,\d+/);
						if (coordMatch) {
						const playerCoords = coordMatch[0].split(',').map(Number);
						const targetCoords = [this.selectedPoint.x, this.selectedPoint.y];
						distance = Math.round(Math.sqrt(Math.pow(playerCoords[0] - targetCoords[0], 2) + Math.pow(playerCoords[1] - targetCoords[1], 2)) * 10);
                            distanceText = `<br><br><strong>Khoảng cách:</strong> ${distance.toLocaleString()} km`;
                        }
                    }
                    this.infoPanel.innerHTML = `<h4>Đã chọn: ${locationString.split('|')[0]}</h4><p>${description}${distanceText}</p><button id="confirm-location-btn" class="major-action-button">${this.isWorldMap ? 'Đến nơi này' : 'Xác nhận nơi này'}</button>`;
                    document.getElementById('confirm-location-btn').onclick = () => { this.onSelectCallback(finalLocation, distance); };
                } else if (mousePos) {
                    this.infoPanel.innerHTML = `<p>Tọa độ: (${Math.round(mousePos.x)}, ${Math.round(mousePos.y)})</p>`;
                } else {
                    this.infoPanel.innerHTML = `<p>Nhấp vào bản đồ để chọn một ${this.isWorldMap ? 'điểm đến' : 'điểm xuất phát'}。</p>`;
                }
            }
        }

