		  let confirmMessage = 'Bạn có chắc chắn muốn xóa vĩnh viễn các mục sau không?\nThao tác này không thể hoàn tác!\n';
		  if (itemsToDelete.main_region.size > 0) confirmMessage += `\nVùng chính: ${[...itemsToDelete.main_region].join(', ')}`;
		  if (itemsToDelete.sub_region.size > 0) confirmMessage += `\nVùng con: ${[...itemsToDelete.sub_region].join(', ')}`;
		  if (itemsToDelete.poi.size > 0) confirmMessage += `\nĐiểm quan tâm: ${[...itemsToDelete.poi].join(', ')}`;

		  if (await showCustomConfirm(confirmMessage)) {
			WORLD_MAP_DATA.main_regions = WORLD_MAP_DATA.main_regions.filter(item => !itemsToDelete.main_region.has(item.name));
			WORLD_MAP_DATA.sub_regions = WORLD_MAP_DATA.sub_regions.filter(item => !itemsToDelete.sub_region.has(item.name));
			WORLD_MAP_DATA.points_of_interest = WORLD_MAP_DATA.points_of_interest.filter(item => !itemsToDelete.poi.has(item.name));

